type FlashcardMediaLike =
  | string
  | {
      remoteUrl?: string | null;
      localUrl?: string | null;
      url?: string | null;
    };

type FlashcardCardLike = {
  id?: string;
  cardId?: string;
  has_uncertainty?: boolean;
  hasUncertainty?: boolean;
  is_bookmarked?: boolean;
  isBookmarked?: boolean;
  question_text?: string;
  questionText?: string;
  answer_text?: string;
  answerText?: string;
  question_images?: FlashcardMediaLike[];
  questionImages?: FlashcardMediaLike[];
  answer_images?: FlashcardMediaLike[];
  answerImages?: FlashcardMediaLike[];
  question_audios?: FlashcardMediaLike[];
  questionAudios?: FlashcardMediaLike[];
  answer_audios?: FlashcardMediaLike[];
  answerAudios?: FlashcardMediaLike[];
  questionCode?: { code?: string; language?: string } | null;
  question_code?: { code?: string; language?: string } | null;
  answerCode?: { code?: string; language?: string } | null;
  answer_code?: { code?: string; language?: string } | null;
  questionBlocks?: CardBlock[];
  answerBlocks?: CardBlock[];
  layoutRows?: number;
  layout_rows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  questionExtraRows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  question_extra_rows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  answerExtraRows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  answer_extra_rows?: number;
  inkQuestion?: InkDocument | null;
  inkAnswer?: InkDocument | null;
  [key: string]: unknown;
};

interface FlashcardProps {
  card: FlashcardCardLike | null | undefined;
  isFlipped?: boolean;
  onFlip?: () => void;
  onEdit?: (card: FlashcardCardLike) => void;
  onToggleUncertainty?: (card: FlashcardCardLike) => void;
  onToggleBookmark?: (card: FlashcardCardLike) => void;
  className?: string;
  onNext?: () => void;
  onPrev?: () => void;
  hasNext?: boolean;
  hasPrev?: boolean;
  currentIndex?: number;
  totalCards?: number;
  previewMode?: boolean;
  extraHeaderLeft?: React.ReactNode;
  extraHeaderRight?: React.ReactNode;
  extraFooter?: React.ReactNode;
  drawMode?: boolean;
  inkEditingEnabled?: boolean;
  onInkDocumentChange?: (
    side: "question" | "answer",
    nextDocument: InkDocument,
  ) => void;
  allowUpscale?: boolean;
  maxScale?: number;
  scaleMultiplier?: number;
  contentPaddingPx?: number;
}

export function Flashcard({
  card,
  isFlipped,
  onFlip,
  onEdit,
  onToggleUncertainty,
  onToggleBookmark,
  className,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  currentIndex,
  totalCards,
  previewMode,
  extraHeaderLeft,
  extraHeaderRight,
  extraFooter,
  drawMode,
  inkEditingEnabled = false,
  onInkDocumentChange,
  allowUpscale = false,
  maxScale = 1.6,
  scaleMultiplier = 1,
  contentPaddingPx,
}: FlashcardProps) {
  const cardData = card;
  const { updateCard } = useCards();

  const [previewFlipped, setPreviewFlipped] = useState(false);

  const [isImageModalOpen, setIsImageModalOpen] = useState(false);
  const [isReferencePopupOpen, setIsReferencePopupOpen] = useState(false);
  const [isImagePopupOpen, setIsImagePopupOpen] = useState(false);
  const [isAudioPopupOpen, setIsAudioPopupOpen] = useState(false);

  const previewInkRef = useRef<InkLayerHandle | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);
  const [previewInkTool, setPreviewInkTool] = useState<InkEditTool | null>(
    null,
  );
  const [previewInkHistory, setPreviewInkHistory] = useState<InkHistoryState>({
    canUndo: false,
    canRedo: false,
    strokeCount: 0,
  });
  const [layoutStable, setLayoutStable] = useState(false);

  // ✅ side も含めて保持（debounce中のflipでも保存先を間違えない）
  const pendingInkRef = useRef<{
    side: "question" | "answer";
    doc: InkDocument;
  } | null>(null);
  const inkSaveTimerRef = useRef<number | null>(null);

  // ---- 先に派生値を確定（TDZ回避） ----
  const cardIdForInk = cardData?.id ?? cardData?.cardId ?? null;
  const enableDrawMode = drawMode ?? false;
  const effectiveIsFlipped =
    isFlipped ?? (previewMode ? previewFlipped : false);
  const activeInkSide: "question" | "answer" = effectiveIsFlipped
    ? "answer"
    : "question";

  useEffect(() => {
    if (!previewMode) return;
    queueMicrotask(() => setPreviewFlipped(false));
  }, [previewMode, cardData?.id]);

  useEffect(() => {
    if (!inkEditingEnabled) {
      queueMicrotask(() => setPreviewInkTool(null));
      return;
    }
    queueMicrotask(() => setPreviewInkTool((prev) => prev ?? "pen"));
  }, [inkEditingEnabled]);

  useEffect(() => {
    if (!previewMode || !inkEditingEnabled) {
      queueMicrotask(() => setLayoutStable(false));
      return;
    }

    let cancelled = false;
    let settleTimer: number | null = null;
    let resizeObserver: ResizeObserver | null = null;

    const scheduleStable = () => {
      if (cancelled) return;
      if (settleTimer != null) {
        window.clearTimeout(settleTimer);
      }
      settleTimer = window.setTimeout(() => {
        if (!cancelled) {
          setLayoutStable(true);
        }
      }, 250);
    };

    const init = async () => {
      setLayoutStable(false);

      const fontsReady = (
        document as Document & { fonts?: { ready?: Promise<unknown> } }
      ).fonts?.ready;
      if (fontsReady && typeof fontsReady.then === "function") {
        try {
          await fontsReady;
        } catch {
          // ignore
        }
      }
      if (cancelled) return;

      const root = contentRef.current;
      if (!root) {
        scheduleStable();
        return;
      }

      const images = Array.from(root.querySelectorAll("img"));
      const imageWaiters = images
        .filter((img) => !img.complete)
        .map(
          (img) =>
            new Promise<void>((resolve) => {
              const done = () => {
                img.removeEventListener("load", done);
                img.removeEventListener("error", done);
                resolve();
              };
              img.addEventListener("load", done, { once: true });
              img.addEventListener("error", done, { once: true });
            }),
        );

      if (imageWaiters.length > 0) {
        await Promise.allSettled(imageWaiters);
      }
      if (cancelled) return;

      scheduleStable();

      if (typeof ResizeObserver !== "undefined") {
        resizeObserver = new ResizeObserver(() => {
          setLayoutStable(false);
          scheduleStable();
        });
        resizeObserver.observe(root);
      }
    };

    void init();
    return () => {
      cancelled = true;
      if (settleTimer != null) {
        window.clearTimeout(settleTimer);
      }
      if (resizeObserver) {
        resizeObserver.disconnect();
      }
    };
  }, [cardData?.id, effectiveIsFlipped, inkEditingEnabled, previewMode]);

  // 参考リンク抽出
  const questionReferences = React.useMemo(() => {
    const extractReferences = (block: CardBlock): ReferenceBlockData[] => {
      const maybeBlock = block as CardBlock & { references?: unknown };
      const refs = maybeBlock.references;
      return Array.isArray(refs) ? (refs as ReferenceBlockData[]) : [];
    };
    const refs: ReferenceBlockData[] = [];
    const qBlocks: CardBlock[] = cardData?.questionBlocks ?? [];
    qBlocks.forEach((block) => {
      if (block.type === "reference") refs.push(...extractReferences(block));
    });
    return refs.filter((r) => r.url);
  }, [cardData?.questionBlocks]);

  const answerReferences = React.useMemo(() => {
    const extractReferences = (block: CardBlock): ReferenceBlockData[] => {
      const maybeBlock = block as CardBlock & { references?: unknown };
      const refs = maybeBlock.references;
      return Array.isArray(refs) ? (refs as ReferenceBlockData[]) : [];
    };
    const refs: ReferenceBlockData[] = [];
    const aBlocks: CardBlock[] = cardData?.answerBlocks ?? [];
    aBlocks.forEach((block) => {
      if (block.type === "reference") refs.push(...extractReferences(block));
    });
    return refs.filter((r) => r.url);
  }, [cardData?.answerBlocks]);

  // 安全なプロパティアクセス（異なる命名規則への対応）
  const hasUncertainty = card?.has_uncertainty ?? card?.hasUncertainty ?? false;
  const isBookmarked = card?.is_bookmarked ?? card?.isBookmarked ?? false;

  const questionText = cardData?.question_text ?? cardData?.questionText ?? "";
  const questionImages =
    cardData?.question_images ?? cardData?.questionImages ?? [];
  const questionAudios =
    cardData?.question_audios ?? cardData?.questionAudios ?? [];

  const answerText = cardData?.answer_text ?? cardData?.answerText ?? "";
  const answerImages = cardData?.answer_images ?? cardData?.answerImages ?? [];
  const answerAudios = cardData?.answer_audios ?? cardData?.answerAudios ?? [];

  const questionCode =
    cardData?.questionCode || cardData?.question_code || null;
  const answerCode = cardData?.answerCode || cardData?.answer_code || null;

  const legacyQuestionExtraRows = normalizeExtraRows(
    cardData?.questionExtraRows ?? cardData?.question_extra_rows ?? 0,
  );
  const legacyAnswerExtraRows = normalizeExtraRows(
    cardData?.answerExtraRows ?? cardData?.answer_extra_rows ?? 0,
  );

  // ✅ B案（raw/safe分離 + finiteガード）
  const rawLayoutRows =
    cardData?.layoutRows ??
    cardData?.layout_rows ??
    LEGACY_BASE_LAYOUT_ROWS +
      Math.max(legacyQuestionExtraRows, legacyAnswerExtraRows);

  const safeLayoutRows = Number.isFinite(rawLayoutRows)
    ? rawLayoutRows
    : DEFAULT_LAYOUT_ROWS;
  const layoutRows = normalizeLayoutRows(safeLayoutRows);

  const questionInkDocument = React.useMemo(
    () =>
      resolveInkDocument(
        cardIdForInk,
        "question",
        cardData?.inkQuestion ?? null,
      ),
    [cardData?.inkQuestion, cardIdForInk],
  );

  const answerInkDocument = React.useMemo(
    () =>
      resolveInkDocument(cardIdForInk, "answer", cardData?.inkAnswer ?? null),
    [cardData?.inkAnswer, cardIdForInk],
  );

  const questionImageUrls = (questionImages ?? [])
    .map(
      (image: unknown) =>
        image?.remoteUrl ?? image?.localUrl ?? image?.url ?? image,
    )
    .filter(Boolean);

  const answerImageUrls = (answerImages ?? [])
    .map(
      (image: unknown) =>
        image?.remoteUrl ?? image?.localUrl ?? image?.url ?? image,
    )
    .filter(Boolean);

  const handleGalleryFullscreenChange = React.useCallback(
    (isFullscreen: boolean) => {
      setIsImageModalOpen(isFullscreen);
    },
    [],
  );

  const activeReferences = effectiveIsFlipped
    ? answerReferences
    : questionReferences;
  const activeInkDocument = effectiveIsFlipped
    ? answerInkDocument
    : questionInkDocument;

  // Flip阻害条件を集約（増えてもここだけ直せば良い）
  const isModalBlockingFlip =
    isImageModalOpen ||
    isImagePopupOpen ||
    isAudioPopupOpen ||
    isReferencePopupOpen;

  const isInkEditingActive = Boolean(
    previewMode && inkEditingEnabled && previewInkTool,
  );

  // ✅ stable になってからマウント（書けない/ズレないを優先）
  const shouldMountInkLayer = Boolean(
    previewMode && inkEditingEnabled && cardIdForInk && layoutStable,
  );

  const flushPendingInk = React.useCallback(() => {
    if (!cardIdForInk) return;

    const pending = pendingInkRef.current;
    if (!pending) return;

    pendingInkRef.current = null;

    updateCard(
      cardIdForInk,
      pending.side === "question"
        ? { inkQuestion: pending.doc }
        : { inkAnswer: pending.doc },
    ).catch((error) => {
      console.error("[Flashcard] Failed to persist ink document", error);
    });
  }, [cardIdForInk, updateCard]);

  const handleInkDocumentChange = React.useCallback(
    (side: "question" | "answer", nextDocument: InkDocument) => {
      const next: InkDocument = {
        ...nextDocument,
        version: nextDocument.version ?? INK_DOCUMENT_VERSION,
        updatedAt: Date.now(),
      };

      onInkDocumentChange?.(side, next);

      // ✅ side も一緒に保持
      pendingInkRef.current = { side, doc: next };

      if (inkSaveTimerRef.current != null) {
        window.clearTimeout(inkSaveTimerRef.current);
      }
      inkSaveTimerRef.current = window.setTimeout(() => {
        flushPendingInk();
        inkSaveTimerRef.current = null;
      }, 300);
    },
    [flushPendingInk, onInkDocumentChange],
  );

  useEffect(() => {
    return () => {
      if (inkSaveTimerRef.current != null) {
        window.clearTimeout(inkSaveTimerRef.current);
      }
      flushPendingInk();
    };
  }, [flushPendingInk]);

  const handleFlip = React.useCallback(
    (e?: React.MouseEvent) => {
      if (isModalBlockingFlip) return;
      if (isInkEditingActive) return;

      if (previewMode) {
        e?.stopPropagation();
        setPreviewFlipped((prev) => !prev);
        return;
      }

      if (onFlip) {
        e?.stopPropagation();
        onFlip();
      }
    },
    [isModalBlockingFlip, isInkEditingActive, previewMode, onFlip],
  );

  const actionsTopLeft: React.ReactNode[] = [];
  const actionsTopRight: React.ReactNode[] = [];
  const mediaActionNodes: React.ReactNode[] = [];
  // extraHeaderLeft は名前通り TopLeft 側へ
  if (extraHeaderLeft) {
    actionsTopLeft.push(
      <div
        key="extra-header-left"
        className="flex"
        onClick={(e) => e.stopPropagation()}
      >
        {extraHeaderLeft}
      </div>,
    );
  }

  // 有効な画像（ブロックではなくポップアップ用）
  const activeImages = effectiveIsFlipped ? answerImageUrls : questionImageUrls;

  if (activeImages.length > 0) {
    mediaActionNodes.push(
      <button
        key="images"
        onClick={(e) => {
          e.stopPropagation();
          setIsImagePopupOpen(true);
        }}
        className="flex items-center gap-1 px-2 py-1 h-8 min-h-0 min-w-0 rounded-full bg-indigo-500 text-white shadow-[0_2px_0_#4338ca] active:shadow-none active:translate-y-[2px] transition-all hover:bg-indigo-400 hover:shadow-[0_2px_0_#4338ca]"
      >
        <ImageIcon className={CARD_ACTION_ICON_CLASS} />
        <span className="text-[10px] font-bold">x{activeImages.length}</span>
      </button>,
    );
  }

  // 有効な音声
  const activeAudios = effectiveIsFlipped ? answerAudios : questionAudios;

  // データ構造の正規化（urlプロパティを持つオブジェクトか、文字列か）
  const toMediaUrl = React.useCallback(
    (m: FlashcardMediaLike): string | null => {
      if (typeof m === "string") return m;
      return m.remoteUrl ?? m.localUrl ?? m.url ?? null;
    },
    [],
  );

  const activeAudioUrls = React.useMemo(
    () =>
      (activeAudios ?? [])
        .map(toMediaUrl)
        .filter((u): u is string => Boolean(u)),
    [activeAudios, toMediaUrl],
  );

  if (activeAudioUrls.length > 0) {
    mediaActionNodes.push(
      <button
        key="audios"
        onClick={(e) => {
          e.stopPropagation();
          setIsAudioPopupOpen(true);
        }}
        className="flex items-center gap-1 px-2 py-1 h-8 min-h-0 min-w-0 rounded-full transition-all bg-amber-500 text-white shadow-[0_2px_0_#b45309] active:shadow-none active:translate-y-[2px] hover:bg-amber-400 hover:shadow-[0_2px_0_#b45309]"
      >
        <Volume2 className={CARD_ACTION_ICON_CLASS} />
        <span className="text-[10px] font-bold">x{activeAudioUrls.length}</span>
      </button>,
    );
  }

  if (activeReferences.length > 0) {
    mediaActionNodes.push(
      <button
        key="references"
        onClick={(e) => {
          e.stopPropagation();
          setIsReferencePopupOpen(true);
        }}
        className="flex items-center gap-1 px-2 py-1 h-8 min-h-0 min-w-0 rounded-full transition-all bg-cyan-500 text-white shadow-[0_2px_0_#0e7490] active:shadow-none active:translate-y-[2px] hover:bg-cyan-400"
      >
        <Link className={CARD_ACTION_ICON_CLASS} />
        <span className="text-[10px] font-bold">
          x{activeReferences.length}
        </span>
      </button>,
    );
  }

  if (mediaActionNodes.length > 0) {
    actionsTopRight.push(
      <div
        key="media-actions"
        className="flex items-center gap-2"
        onClick={(e) => e.stopPropagation()}
      >
        {mediaActionNodes}
      </div>,
    );
  }

  // アクション表示（編集(onEdit)以外はプレビューでも表示）
  if (onToggleUncertainty || onToggleBookmark) {
    actionsTopLeft.push(
      <CardCornerActions
        key="corner-actions"
        onHelp={
          onToggleUncertainty ? () => onToggleUncertainty(cardData) : undefined
        }
        onStar={onToggleBookmark ? () => onToggleBookmark(cardData) : undefined}
        helpActive={hasUncertainty}
        starActive={isBookmarked}
      />,
    );
  }

  if (onEdit && !previewMode) {
    actionsTopRight.push(
      <Button
        key="edit"
        variant="ghost"
        size="icon"
        onClick={(e) => {
          e.stopPropagation();
          onEdit(cardData);
        }}
        className={cn(
          "rounded-none w-8 h-8 md:w-9 md:h-9 transition-colors",
          CARD_ACTION_BG_CLASS,
          CARD_ACTION_COLOR_IDLE_CLASS,
        )}
      >
        <Edit className={CARD_ACTION_ICON_CLASS} />
      </Button>,
    );
  }

  const resolveSideBlocks = React.useCallback(
    (side: "question" | "answer"): CardBlock[] => {
      const sideBlocks =
        side === "question"
          ? (cardData?.questionBlocks ?? [])
          : (cardData?.answerBlocks ?? []);
      if (sideBlocks.length > 0) {
        return sortBlocksByOrderIndex(sideBlocks);
      }

      const text = side === "question" ? questionText : answerText;
      const images = side === "question" ? questionImageUrls : answerImageUrls;
      const audios = side === "question" ? questionAudios : answerAudios;
      const code = side === "question" ? questionCode : answerCode;

      const fallbackBlocks: CardBlock[] = [];
      let orderIndex = 0;

      if ((text ?? "").trim() !== "") {
        fallbackBlocks.push({
          id: `${side}-legacy-text`,
          type: "text",
          orderIndex: orderIndex++,
          content: String(text),
        } as CardBlock);
      }

      if ((code?.code ?? "").trim() !== "") {
        fallbackBlocks.push({
          id: `${side}-legacy-code`,
          type: "code",
          orderIndex: orderIndex++,
          code,
        } as CardBlock);
      }

      if ((images?.length ?? 0) > 0) {
        fallbackBlocks.push({
          id: `${side}-legacy-image`,
          type: "image",
          orderIndex: orderIndex++,
          images: images as unknown as CardBlock["images"],
        } as CardBlock);
      }

      if ((audios?.length ?? 0) > 0) {
        fallbackBlocks.push({
          id: `${side}-legacy-audio`,
          type: "audio",
          orderIndex,
          audios: audios as unknown as CardBlock["audios"],
        } as CardBlock);
      }

      return fallbackBlocks;
    },
    [
      answerAudios,
      answerCode,
      answerImageUrls,
      answerText,
      cardData?.answerBlocks,
      cardData?.questionBlocks,
      questionAudios,
      questionCode,
      questionImageUrls,
      questionText,
    ],
  );

  // overlay を安定化（Inkが余計に再マウント/再描画されにくい）
  const overlayNode = React.useMemo(() => {
    const hasHeaderOverlay = Boolean(extraHeaderRight && !previewMode);
    const hasFooterOverlay = Boolean(extraFooter);
    const hasInkOverlay = Boolean(
      previewMode && inkEditingEnabled && cardIdForInk,
    );
    if (!hasHeaderOverlay && !hasFooterOverlay && !hasInkOverlay) return null;

    return (
      <>
        {hasHeaderOverlay && (
          <div className="absolute right-2 top-2 z-30 pointer-events-none">
            <div
              className="pointer-events-auto"
              onClick={(e) => e.stopPropagation()}
            >
              {extraHeaderRight}
            </div>
          </div>
        )}
        {hasFooterOverlay && (
          <div className="absolute inset-x-0 bottom-2 z-30 pointer-events-none">
            <div
              className="flex justify-center pointer-events-auto"
              onClick={(e) => e.stopPropagation()}
            >
              {extraFooter}
            </div>
          </div>
        )}
        {hasInkOverlay && (
          <>
            {shouldMountInkLayer && (
              <InkLayer
                ref={previewInkRef}
                cardId={cardIdForInk}
                side={activeInkSide}
                editable={Boolean(
                  previewMode && inkEditingEnabled && layoutStable,
                )}
                tool={previewInkTool ?? "pen"}
                value={activeInkDocument}
                onChange={(next) =>
                  handleInkDocumentChange(activeInkSide, next)
                }
                onHistoryChange={setPreviewInkHistory}
              />
            )}

            {previewMode && inkEditingEnabled && !layoutStable && (
              <div className="absolute inset-0 z-20 flex items-center justify-center bg-white/25 text-slate-600 text-xs font-semibold">
                レイアウト準備中...
              </div>
            )}

            {/* ✅ stable 前は ref が null なので出さない */}
            {previewMode && inkEditingEnabled && layoutStable && (
              <div className="absolute bottom-2 left-2 z-30 pointer-events-auto">
                <InkToolbar
                  tool={previewInkTool}
                  canUndo={previewInkHistory.canUndo}
                  canRedo={previewInkHistory.canRedo}
                  onToolChange={setPreviewInkTool}
                  onUndo={() => previewInkRef.current?.undo()}
                  onRedo={() => previewInkRef.current?.redo()}
                  onClear={() => previewInkRef.current?.clear()}
                />
              </div>
            )}
          </>
        )}
      </>
    );
  }, [
    cardIdForInk,
    handleInkDocumentChange,
    activeInkSide,
    activeInkDocument,
    inkEditingEnabled,
    layoutStable,
    previewInkTool,
    previewInkHistory.canUndo,
    previewInkHistory.canRedo,
    extraFooter,
    extraHeaderRight,
    previewMode,
    shouldMountInkLayer,
  ]);

  const fixedHeightPx = layoutRowsToCardHeightPx(layoutRows);
  if (!cardData) {
    return <div className="text-center py-12 text-gray-500">No Card Data</div>;
  }
  const activeSide: "question" | "answer" = effectiveIsFlipped
    ? "answer"
    : "question";
  const activeBlocks = resolveSideBlocks(activeSide);
  const ruledPhasePx = 0;

  return (
    <div
      className={cn(
        "w-full flex flex-col select-none overflow-visible",
        className,
      )}
    >
      <div className="relative">
        <CardFrame
          baseWidth={CANONICAL_CARD_WIDTH}
          contentPaddingPx={contentPaddingPx ?? 0}
          allowUpscale={allowUpscale}
          maxScale={maxScale}
          scaleMultiplier={scaleMultiplier}
          className={cn(
            "premium-paper-depth",
            !previewMode && "cursor-pointer",
            "card-shell--paper",
          )}
          onClick={handleFlip}
          resizable={false}
          resizeStepPx={undefined}
          showResizeHandle={false}
          heightPx={fixedHeightPx}
          lockHeight
          actionsTopLeft={
            actionsTopLeft.length > 0 ? actionsTopLeft : undefined
          }
          actionsTopRight={
            actionsTopRight.length > 0 ? actionsTopRight : undefined
          }
          drawMode={enableDrawMode}
          ruledPhasePx={ruledPhasePx}
          overlay={overlayNode}
        >
          <div
            ref={contentRef}
            className="animate-in fade-in zoom-in-95 duration-300 w-full max-w-full flex min-h-0 flex-1"
          >
            <SharedCardContent
              mode="view"
              blocks={activeBlocks}
              onGalleryFullscreenChange={handleGalleryFullscreenChange}
            />
          </div>
        </CardFrame>
      </div>

      <ReferencePopup
        isOpen={isReferencePopupOpen}
        onClose={() => setIsReferencePopupOpen(false)}
        references={activeReferences}
      />

      <Dialog open={isImagePopupOpen} onOpenChange={setIsImagePopupOpen}>
        <DialogContent className="max-w-5xl w-full p-0 bg-transparent border-none shadow-none max-h-[90vh] overflow-y-auto">
          <div className="bg-white rounded-2xl p-4 md:p-6 shadow-2xl relative min-h-[200px]">
            <Button
              variant="ghost"
              size="icon"
              className="absolute right-2 top-2 z-10 rounded-full bg-slate-100/80 hover:bg-slate-200 text-slate-500"
              onClick={() => setIsImagePopupOpen(false)}
            >
              <X className="w-5 h-5" />
            </Button>
            <div className="mt-8 space-y-4">
              {activeImages.map((url, index) => (
                <div key={`${url}-${index}`} className="w-full">
                  <img
                    src={url}
                    alt={`Image ${index + 1}`}
                    className="w-full h-auto rounded-lg border border-slate-100 shadow-sm"
                  />
                </div>
              ))}
            </div>
            {activeImages.length === 0 && (
              <div className="flex items-center justify-center py-20 text-slate-400">
                画像がありません
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={isAudioPopupOpen} onOpenChange={setIsAudioPopupOpen}>
        <DialogContent className="sm:max-w-md w-full bg-white border-none shadow-2xl p-6 rounded-2xl">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-slate-700 flex items-center gap-2">
              <Volume2 className="w-5 h-5 text-amber-500" />
              音声再生
            </h3>
            <Button
              variant="ghost"
              size="icon"
              className="rounded-full hover:bg-slate-100 text-slate-400"
              onClick={() => setIsAudioPopupOpen(false)}
            >
              <X className="w-5 h-5" />
            </Button>
          </div>

          <div className="py-2">
            <AudioPlayer urls={activeAudioUrls} />
          </div>

          {activeAudioUrls.length === 0 && (
            <div className="text-center py-8 text-slate-400 text-sm">
              音声がありません
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* ナビゲーション（オプション） - プレビュー時は非表示 */}
      {!previewMode &&
        (onNext ||
          onPrev ||
          (currentIndex !== undefined && totalCards !== undefined)) && (
          <div className="flex items-center justify-between mt-8 px-4">
            <Button
              variant="ghost"
              onClick={onPrev}
              disabled={
                !hasPrev &&
                (!onPrev || (currentIndex !== undefined && currentIndex === 0))
              }
              className="text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full h-12 px-6"
            >
              <ChevronLeft className="w-5 h-5 mr-2" />
              <span className="font-medium">Previous</span>
            </Button>

            {currentIndex !== undefined && totalCards !== undefined && (
              <span className="text-sm font-bold text-slate-300 tracking-widest">
                {currentIndex + 1} / {totalCards}
              </span>
            )}

            <Button
              variant="ghost"
              onClick={onNext}
              disabled={
                !hasNext &&
                (!onNext ||
                  (currentIndex !== undefined &&
                    totalCards !== undefined &&
                    currentIndex === totalCards - 1))
              }
              className="text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full h-12 px-6"
            >
              <span className="font-medium">Next</span>
              <ChevronRight className="w-5 h-5 ml-2" />
            </Button>
          </div>
        )}
    </div>
  );
}

import React, { useCallback, useState, useEffect, useRef, useId } from "react";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { Upload, X, Play, Pause, RotateCcw, Check } from "@/ui/icons";
import { cn } from "@/lib/utils";
import { useAuth } from "@/contexts/AuthContext";
import type { UploadedImage, AssetRecord } from "@/types";
import {
  createUploadedImage,
  createFailedUploadedImage,
  isHeicFile,
  convertHeicToJpeg,
} from "@/utils/imageUtils";
import type { UploadedImageStatus } from "@/types";
import type { StorageUrl } from "@/types/branded";
import { useReliableFileUpload } from "@/hooks/useReliableFileUpload";
import { ImageFrame } from "../blocks/ImageFrame";
import { putImageBlob, deleteImageBlob } from "@/services/imageFileStore";
import {
  getOrCreateImageBlobUrl,
  removeImageBlobUrl,
} from "@/services/imageBlobUrlSessionCache";
import { getLocalDb } from "@/services/localDB";

const clamp = (v: number, min: number, max: number) =>
  Math.min(max, Math.max(min, v));

function ImageItem({ item, index, onRetry, onUpdate }) {
  const [loadFailed, setLoadFailed] = useState(false);
  const { currentUser } = useAuth();
  const [resolvedLocalUrl, setResolvedLocalUrl] = useState<string | null>(null);
  const displayUrl = item.remoteUrl ?? item.localUrl ?? resolvedLocalUrl ?? "";
  const isFailed = item.status === "failed";
  const safeScale = clamp(Number(item.scale ?? 1), 0.2, 1);
  useEffect(() => {
    queueMicrotask(() => setLoadFailed(false));
  }, [displayUrl]);
  useEffect(() => {
    const localFileId = item?.localFileId;
    if (!localFileId) {
      queueMicrotask(() => setResolvedLocalUrl(null));
      return;
    }
    if (item?.remoteUrl || item?.localUrl) return;
    let cancelled = false;
    const run = async () => {
      const url = await getOrCreateImageBlobUrl(localFileId, {
        userId: currentUser?.uid,
      });
      if (cancelled) return;
      setResolvedLocalUrl(url);
    };
    void run();
    return () => {
      cancelled = true;
    };
  }, [currentUser?.uid, item?.localFileId, item?.localUrl, item?.remoteUrl]);

  return (
    <>
      <div className="relative group rounded-lg overflow-hidden w-full">
        {displayUrl && !loadFailed ? (
          <ImageFrame
            src={displayUrl}
            alt={`Image ${index + 1}`}
            className="bg-transparent"
            imgClassName="cursor-pointer"
            scale={item.scale ?? 1}
            x={item.x ?? 0}
            naturalW={item.naturalW ?? null}
            naturalH={item.naturalH ?? null}
            editable
            onError={() => setLoadFailed(true)}
            onNaturalSize={({ naturalW, naturalH }) => {
              if (
                (item.naturalW ?? 0) === naturalW &&
                (item.naturalH ?? 0) === naturalH
              )
                return;
              onUpdate(index, { naturalW, naturalH });
            }}
            onTransformChange={({ scale, x }) => {
              onUpdate(index, { scale, x });
            }}
          />
        ) : (
          <div className="w-full h-48 bg-white flex items-center justify-center text-slate-400 text-xs">
            画像を表示できません
          </div>
        )}
        {displayUrl && !loadFailed && (
          <div className="pointer-events-none absolute inset-x-3 bottom-2 z-30 opacity-0 group-hover:opacity-100 group-focus-within:opacity-100 supports-[hover:none]:opacity-100 transition-opacity">
            <div
              className="pointer-events-auto ml-auto w-full max-w-[300px] rounded-lg border border-slate-200/70 bg-white/75 px-2 py-1 shadow-sm backdrop-blur"
              onPointerDown={(event) => event.stopPropagation()}
            >
              <Slider
                min={20}
                max={100}
                step={1}
                value={[Math.round(safeScale * 100)]}
                onValueChange={(values) => {
                  const nextScaleRaw = clamp((values[0] ?? 100) / 100, 0.2, 1);
                  const nextScale = nextScaleRaw >= 0.98 ? 1 : nextScaleRaw;
                  const baseX =
                    nextScale >= 0.999 ? 0 : clamp(Number(item.x ?? 0), -1, 1);
                  onUpdate(index, { scale: nextScale, x: baseX });
                }}
                className="w-full scale-[0.92]"
                aria-label="画像サイズ"
              />
            </div>
          </div>
        )}

        {/* Optimistic Status Badges & Progress */}
        <div className="absolute inset-x-2 bottom-2 z-20">
          {item.status === "uploading" &&
            item.progress !== undefined &&
            item.progress < 100 && (
              <div className="bg-white/90 rounded-full h-1 overflow-hidden shadow-sm">
                <div
                  className="h-full progress-bar-fill"
                  style={
                    {
                      "--progress": `${item.progress}%`,
                      "--progress-color": "var(--primary-color)",
                    } as React.CSSProperties
                  }
                />
              </div>
            )}
        </div>

        <div className="absolute bottom-1 right-1 flex gap-1 z-20">
          {item.source === "cloud" && (
            <div className="p-0.5 bg-green-500 rounded-full shadow-sm">
              <Check className="w-3 h-3 text-white" />
            </div>
          )}
          {item.source === "local_fallback" && (
            <div className="p-1.5 bg-amber-500 rounded-full shadow-sm"></div>
          )}
        </div>

        <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          {isFailed && (
            <Button
              variant="secondary"
              size="icon"
              className="h-7 w-7 bg-white/80"
              onClick={() => onRetry(index)}
            >
              <RotateCcw className="w-3 h-3" />
            </Button>
          )}
        </div>
      </div>
    </>
  );
}

function AudioItem({ url, index, onRemove }) {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = React.useRef(null);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  return (
    <div className="flex items-center gap-2 p-2 border rounded-lg bg-gray-50">
      <audio ref={audioRef} src={url} onEnded={() => setIsPlaying(false)} />
      <Button
        variant="outline"
        size="icon"
        className="h-8 w-8"
        onClick={togglePlay}
      >
        {isPlaying ? (
          <Pause className="w-4 h-4" />
        ) : (
          <Play className="w-4 h-4" />
        )}
      </Button>
      <span className="flex-1 text-sm text-gray-600 truncate">
        音声 {index + 1}
      </span>
      <Button
        variant="ghost"
        size="icon"
        className="h-7 w-7 text-red-500 hover:bg-red-50"
        onClick={() => onRemove(index)}
      >
        <X className="w-3 h-3" />
      </Button>
    </div>
  );
}

interface MediaUploaderProps {
  type?: "image" | "audio";
  urls?: (string | UploadedImage)[];
  onChange: (urls: (string | UploadedImage)[]) => void;
  maxFiles?: number;
  initialFile?: File;
  onConsumeInitialFile?: () => void;
  onFilesExcess?: (files: File[]) => void;
  autoOpenPicker?: boolean;
}

export default function MediaUploader({
  type = "image",
  urls = [],
  onChange,
  maxFiles = 10,
  initialFile,
  onConsumeInitialFile,
  onFilesExcess,
  autoOpenPicker = false,
}: MediaUploaderProps) {
  const { currentUser } = useAuth();
  const [isUploading, setIsUploading] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const [retryIndex, setRetryIndex] = useState<number | null>(null);
  const latestItemsRef = useRef(urls);
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const autoOpenedRef = useRef(false);

  const uniqueId = useId();
  const inputId = `file-${type}-${uniqueId}`;

  // Handle initialFile (pending upload from overflow)
  useEffect(() => {
    if (initialFile && onConsumeInitialFile) {
      // Automatically start uploading the file
      handleUpload([initialFile]);
      // Notify parent that the file has been consumed so it can be cleared from state
      onConsumeInitialFile();
    }
  }, [initialFile]);

  useEffect(() => {
    latestItemsRef.current = urls;
  }, [urls]);

  useEffect(() => {
    if (!autoOpenPicker) {
      autoOpenedRef.current = false;
      return;
    }
    if (autoOpenedRef.current) return;

    const trigger = () => {
      if (!fileInputRef.current) return;
      autoOpenedRef.current = true;
      fileInputRef.current.click();
    };

    const rafId = window.requestAnimationFrame(trigger);
    return () => window.cancelAnimationFrame(rafId);
  }, [autoOpenPicker, urls.length, type]);

  const accept =
    type === "image"
      ? "image/png,image/jpeg,image/jpg,image/heic,image/heif"
      : "audio/*";

  const ariaLabel =
    type === "image" ? "画像をアップロード" : "音声をアップロード";

  const { uploadFile } = useReliableFileUpload();

  // Helper to generate storage path
  const getStoragePath = (uid: string) => (fileName: string) =>
    `users/${uid}/uploads/${fileName}`;
  const buildAssetRemoteKey = useCallback(
    (uid: string, assetId: string) => `users/${uid}/assets/${assetId}`,
    [],
  );
  const upsertAssetRecord = useCallback(
    async (asset: AssetRecord) => {
      const db = await getLocalDb(currentUser?.uid);
      await db.images.put(asset as any);
    },
    [currentUser?.uid],
  );
  const enqueueAssetUpload = useCallback(
    async (payload: {
      assetId: string;
      localBlobId: string;
      remoteKey: string;
      mime: string;
      size: number;
    }) => {
      const db = await getLocalDb(currentUser?.uid);
      const now = Date.now();
      const existing = await db.syncQueue
        .where("targetId")
        .equals(payload.assetId)
        .filter(
          (item: unknown) =>
            item.entity === "asset" && item.status === "pending",
        )
        .first();
      if (existing) return;
      await db.syncQueue.add({
        id: crypto.randomUUID(),
        idempotencyKey: crypto.randomUUID(),
        targetId: payload.assetId,
        entity: "asset",
        operationType: "update",
        type: "upload",
        action: "update",
        payload,
        priority: "high",
        createdAt: now,
        updatedAt: now,
        status: "pending",
        retryCount: 0,
      } as any);
      if (import.meta.env.DEV) {
        console.info("[Asset] Enqueued upload", payload);
      }
    },
    [currentUser?.uid],
  );

  const handleUpload = async (files: FileList | File[]) => {
    if (!files || files.length === 0) return;

    // 認証チェック
    if (!currentUser) {
      alert("画像をアップロードするにはログインが必要です。");
      return;
    }

    const isImage = type === "image";
    const currentCount = urls.length;
    const limit = Math.max(0, maxFiles - currentCount);

    // Convert to array
    const allFiles = Array.from(files);

    // Split into current vs excess
    const filesToUpload = allFiles.slice(0, limit);
    const filesExcess = allFiles.slice(limit);

    // Notify parent about excess files
    if (filesExcess.length > 0 && onFilesExcess) {
      onFilesExcess(filesExcess);
    }

    if (filesToUpload.length === 0) {
      return;
    }

    const filesArray = filesToUpload;

    if (!isImage) {
      setIsUploading(true);
      try {
        const uploadAudioWrapper = async (file: File) => {
          return await uploadFile(file, getStoragePath(currentUser.uid), {
            type: "card_audio",
          });
        };

        // maxFiles=1 の場合は最初の1ファイルのみ処理
        const filesToUpload =
          maxFiles === 1 ? filesArray.slice(0, 1) : filesArray;
        const results = await Promise.allSettled(
          filesToUpload.map(uploadAudioWrapper),
        );
        const uploadedUrls = results
          .filter((result) => result.status === "fulfilled")
          .map((result: unknown) => result.value.url);

        if (uploadedUrls.length > 0) {
          if (maxFiles === 1) {
            // 単一ファイル制限の場合は置き換え
            onChange([uploadedUrls[0]]);
          } else {
            onChange([...(urls as string[]), ...uploadedUrls]);
          }
        }

        const failures = results.filter((r) => r.status === "rejected");
        if (failures.length > 0) {
          console.error("Audio upload failures:", failures);
          alert(`${failures.length}件のファイルのアップロードに失敗しました。`);
        }
      } catch (error: unknown) {
        console.error("[MediaUploader] Audio upload error:", error);
        alert(`ファイルのアップロードに失敗しました: ${error.message}`);
      } finally {
        setIsUploading(false);
      }
      return;
    }

    // Image Upload Logic using Hook
    try {
      const prepared = await Promise.all(
        filesArray.map(async (file) => {
          if (isHeicFile(file)) {
            try {
              const converted = await convertHeicToJpeg(file);
              const image = createUploadedImage(converted);
              const assetId = image.assetId ?? image.id;
              const blobRecord = await putImageBlob(converted, {
                userId: currentUser.uid,
                assetId,
              });
              const previewUrl = await getOrCreateImageBlobUrl(
                blobRecord.localBlobId,
                { userId: currentUser.uid },
              );
              const remoteKey = buildAssetRemoteKey(currentUser.uid, assetId);
              await upsertAssetRecord({
                id: assetId,
                userId: currentUser.uid,
                mime: blobRecord.mime,
                size: blobRecord.size,
                localBlobId: blobRecord.localBlobId,
                localStatus: "present",
                remoteKey,
                remoteStatus: "none",
                createdAt: new Date(),
                updatedAt: new Date(),
              });
              if (import.meta.env.DEV) {
                console.info("[MediaUploader] image asset created", {
                  assetId,
                  localBlobId: blobRecord.localBlobId,
                });
              }
              await enqueueAssetUpload({
                assetId,
                localBlobId: blobRecord.localBlobId,
                remoteKey,
                mime: blobRecord.mime,
                size: blobRecord.size,
              });
              return {
                file: converted,
                image: {
                  ...image,
                  assetId,
                  localFileId: blobRecord.localBlobId,
                  storagePath: remoteKey,
                  localUrl: (previewUrl ?? image.localUrl) as any,
                },
              };
            } catch (error) {
              console.warn("HEIC conversion failed", error);
              return { file: null, image: createFailedUploadedImage(file) };
            }
          }
          const image = createUploadedImage(file);
          const assetId = image.assetId ?? image.id;
          const blobRecord = await putImageBlob(file, {
            userId: currentUser.uid,
            assetId,
          });
          const previewUrl = await getOrCreateImageBlobUrl(
            blobRecord.localBlobId,
            { userId: currentUser.uid },
          );
          const remoteKey = buildAssetRemoteKey(currentUser.uid, assetId);
          await upsertAssetRecord({
            id: assetId,
            userId: currentUser.uid,
            mime: blobRecord.mime,
            size: blobRecord.size,
            localBlobId: blobRecord.localBlobId,
            localStatus: "present",
            remoteKey,
            remoteStatus: "none",
            createdAt: new Date(),
            updatedAt: new Date(),
          });
          if (import.meta.env.DEV) {
            console.info("[MediaUploader] image asset created", {
              assetId,
              localBlobId: blobRecord.localBlobId,
            });
          }
          await enqueueAssetUpload({
            assetId,
            localBlobId: blobRecord.localBlobId,
            remoteKey,
            mime: blobRecord.mime,
            size: blobRecord.size,
          });
          return {
            file,
            image: {
              ...image,
              assetId,
              localFileId: blobRecord.localBlobId,
              storagePath: remoteKey,
              localUrl: (previewUrl ?? image.localUrl) as any,
            },
          };
        }),
      );

      const newImages = [
        ...(urls as UploadedImage[]),
        ...prepared.map((item) => item.image),
      ];
      latestItemsRef.current = newImages;
      onChange(newImages);

      // Process uploads
      await Promise.all(
        prepared.map(async (preparedItem) => {
          if (!preparedItem.file) return;
          const image = preparedItem.image;

          try {
            const result = await uploadFile(
              preparedItem.file,
              () =>
                buildAssetRemoteKey(currentUser.uid, image.assetId ?? image.id),
              { type: "card_image", docId: image.assetId ?? image.id },
              (progress) => {
                // Update progress state
                const current =
                  (latestItemsRef.current as UploadedImage[]) || [];
                const updated = current.map((item) =>
                  item.id === image.id ? { ...item, progress: progress } : item,
                );
                onChange(updated);
              },
            );

            // Ensure cloud sync icon is visible for at least 1 second and force 100%
            const currentMid =
              (latestItemsRef.current as UploadedImage[]) || [];
            const updatedMid = currentMid.map((item) =>
              item.id === image.id ? { ...item, progress: 100 } : item,
            );
            onChange(updatedMid);

            await new Promise((resolve) => setTimeout(resolve, 800));

            const current = (latestItemsRef.current as UploadedImage[]) || [];
            const updated = current.map((item) => {
              if (item.id !== image.id) return item;
              const safeRemoteUrl =
                typeof result.url === "string" && result.url.startsWith("http")
                  ? result.url
                  : null;
              return {
                ...item,
                assetId: item.assetId ?? item.id,
                localFileId: item.localFileId ?? item.assetId ?? item.id,
                localUrl: item.localUrl ?? null,
                remoteUrl: (safeRemoteUrl || null) as StorageUrl | null,
                storagePath: result.storagePath || null,
                status: safeRemoteUrl
                  ? ("ready" as UploadedImageStatus)
                  : ("uploading" as UploadedImageStatus),
                source: result.source || null,
                fallbackReason: result.fallbackReason || null,
                progress: 100, // completed
              };
            });
            latestItemsRef.current = updated; // 最新の状態を保存
            onChange(updated);
          } catch (error: unknown) {
            console.error(
              "[MediaUploader] Image upload error for:",
              image.id,
              error,
            );
            const current = (latestItemsRef.current as UploadedImage[]) || [];
            const updated = current.map((item) =>
              item.id === image.id
                ? {
                    ...item,
                    status: "failed" as UploadedImageStatus,
                    error: error.message,
                  }
                : item,
            );
            latestItemsRef.current = updated; // 最新の状態を保存
            onChange(updated);
          }
        }),
      );
    } catch (error: unknown) {
      console.error("[MediaUploader] Image preparation/upload error:", error);
      alert(`画像のアップロードに失敗しました: ${error.message}`);
    }
  };

  const handleRetry = (index: number) => {
    if (type !== "image") return;
    setRetryIndex(index);
    fileInputRef.current?.click();
  };

  const handleRetryUpload = async (file: File, index: number) => {
    if (!currentUser) {
      alert("画像をアップロードするにはログインが必要です。");
      return;
    }

    const current = (latestItemsRef.current as UploadedImage[]) || [];
    const previous = current[index];
    if (previous?.localUrl) {
      URL.revokeObjectURL(previous.localUrl);
    }

    try {
      const targetFile = isHeicFile(file)
        ? await convertHeicToJpeg(file)
        : file;
      const created = createUploadedImage(targetFile) as UploadedImage;
      const assetId = created.assetId ?? created.id;
      const remoteKey = buildAssetRemoteKey(currentUser.uid, assetId);
      const blobRecord = await putImageBlob(targetFile, {
        userId: currentUser.uid,
        assetId,
      });
      const previewUrl = await getOrCreateImageBlobUrl(blobRecord.localBlobId, {
        userId: currentUser.uid,
      });
      await upsertAssetRecord({
        id: assetId,
        userId: currentUser.uid,
        mime: blobRecord.mime,
        size: blobRecord.size,
        localBlobId: blobRecord.localBlobId,
        localStatus: "present",
        remoteKey,
        remoteStatus: "none",
        createdAt: new Date(),
        updatedAt: new Date(),
      });
      if (import.meta.env.DEV) {
        console.info("[MediaUploader] image asset created", {
          assetId,
          localBlobId: blobRecord.localBlobId,
        });
      }
      await enqueueAssetUpload({
        assetId,
        localBlobId: blobRecord.localBlobId,
        remoteKey,
        mime: blobRecord.mime,
        size: blobRecord.size,
      });
      const newImage = {
        ...created,
        assetId,
        localFileId: blobRecord.localBlobId,
        storagePath: remoteKey,
        localUrl: (previewUrl ?? created.localUrl) as any,
      };
      const replaced = current.map((item, i) =>
        i === index ? newImage : item,
      );
      onChange(replaced);

      const result = await uploadFile(targetFile, () => remoteKey, {
        type: "card_image",
        docId: assetId,
      });

      const after = (latestItemsRef.current as UploadedImage[]) || [];
      const updated = after.map((item) => {
        if (item.id !== newImage.id) return item;
        const safeRemoteUrl =
          typeof result.url === "string" && result.url.startsWith("http")
            ? result.url
            : null;
        return {
          ...item,
          assetId: item.assetId ?? item.id,
          localFileId: item.localFileId ?? item.assetId ?? item.id,
          localUrl: item.localUrl ?? null,
          remoteUrl: (safeRemoteUrl || null) as StorageUrl | null,
          storagePath: result.storagePath || null,
          status: safeRemoteUrl
            ? ("ready" as UploadedImageStatus)
            : ("uploading" as UploadedImageStatus),
          source: result.source || null,
          fallbackReason: result.fallbackReason || null,
        };
      });
      onChange(updated);
    } catch (error: unknown) {
      console.warn("Retry failed", error);
      // Fallback failed or hook threw
      const failedImage = createFailedUploadedImage(file) as UploadedImage;
      const replaced = current.map((item, i) =>
        i === index ? failedImage : item,
      );
      onChange(replaced);
    }
  };

  const handleFileInputChange = (
    event: React.ChangeEvent<HTMLInputElement>,
  ) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    if (retryIndex !== null && type === "image") {
      const file = files[0];
      handleRetryUpload(file, retryIndex);
      setRetryIndex(null);
      event.target.value = "";
      return;
    }

    handleUpload(files);
    event.target.value = "";
  };

  const handleDrop = useCallback(
    (e) => {
      e.preventDefault();
      setDragOver(false);
      handleUpload(e.dataTransfer.files);
    },
    [urls],
  );

  const handleDragOver = (e) => {
    e.preventDefault();
    setDragOver(true);
  };

  const handleDragLeave = () => {
    setDragOver(false);
  };

  // Handle paste for images and audio
  const handlePaste = useCallback(
    async (e) => {
      const target = e.target as HTMLElement | null;
      const isEditableTarget = !!target?.closest(
        'input, textarea, select, [contenteditable="true"]',
      );
      if (isEditableTarget) return;

      // Only handle paste if mouse is hovering over this uploader instance
      if (!containerRef.current?.matches(":hover")) return;

      const items = e.clipboardData?.items;
      if (!items) return;

      const files = [];
      for (const item of items) {
        if (type === "image" && item.type.startsWith("image/")) {
          const file = item.getAsFile();
          if (file) files.push(file);
        } else if (type === "audio" && item.type.startsWith("audio/")) {
          const file = item.getAsFile();
          if (file) files.push(file);
        }
      }

      // We pass ALL files to handleUpload, which now knows how to split them.
      if (files.length > 0) {
        e.preventDefault();
        await handleUpload(files);
      }
    },
    [urls, type, maxFiles, onFilesExcess],
  );

  useEffect(() => {
    document.addEventListener("paste", handlePaste);
    return () => document.removeEventListener("paste", handlePaste);
  }, [handlePaste]);

  const handleRemove = (index: number) => {
    if (type === "image") {
      const items = urls as UploadedImage[];
      const removed = items[index];
      if (removed?.localFileId) {
        removeImageBlobUrl(removed.localFileId, { userId: currentUser?.uid });
        void deleteImageBlob(removed.localFileId, { userId: currentUser?.uid });
      }
      const next = items.filter((_, i) => i !== index);
      onChange(next);
      return;
    }

    const newUrls = (urls as string[]).filter((_, i) => i !== index);
    onChange(newUrls);
  };

  const handleUpdateImage = (index: number, patch: Partial<UploadedImage>) => {
    const current = (latestItemsRef.current as UploadedImage[]) || [];
    const next = current.map((image, i) =>
      i === index ? { ...image, ...patch } : image,
    );
    latestItemsRef.current = next;
    onChange(next);
  };

  return (
    <div className="space-y-3" ref={containerRef}>
      {/* 
          urls が空の場合のみ、大きなアップロードエリアを表示する。
          画像や音声が既に1つ以上ある場合は、この巨大なエリアは隠して
          コンテンツリストの末尾に小さな「追加」ボタンを表示する。
      */}
      {urls.length === 0 && (
        <div
          className={cn(
            "border-2 border-dashed rounded-[24px] p-5 text-center transition-all duration-300 cursor-pointer group/upload",
            dragOver
              ? "border-indigo-400 bg-indigo-50/50"
              : "border-slate-200 hover:border-slate-300 hover:bg-slate-50/30",
          )}
          onDrop={handleDrop}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onClick={() => {
            setRetryIndex(null);
            fileInputRef.current?.click();
          }}
        >
          <input
            hidden
            id={inputId}
            type="file"
            accept={accept}
            multiple
            className="hidden"
            ref={fileInputRef}
            onChange={handleFileInputChange}
            aria-label={ariaLabel}
          />

          {isUploading ? (
            <div className="flex items-center justify-center gap-2 text-indigo-600">
              <Upload className="w-6 h-6 mx-auto mb-1.5 opacity-50" />
              <p className="text-sm">アップロード中...</p>
            </div>
          ) : (
            <div className="text-slate-400 group-hover/upload:text-slate-500 transition-colors select-none">
              <Upload className="w-6 h-6 mx-auto mb-2 opacity-60" />
              <p className="text-[10px] font-bold tracking-widest uppercase">
                ドラッグ＆ドロップ、クリック、または Ctrl+V で
                {type === "image" ? "画像を" : "音声を"}アップロード
              </p>
            </div>
          )}
        </div>
      )}

      {/* 
          隠し input 要素: 
          大きなエリアを隠しても、追加ボタンからクリックイベントを発火させるために必要。
      */}
      {urls.length > 0 && (
        <input
          hidden
          id={`${inputId}-hidden`}
          type="file"
          accept={accept}
          multiple
          className="hidden"
          ref={fileInputRef}
          onChange={handleFileInputChange}
          aria-label={ariaLabel}
        />
      )}

      {urls.length > 0 && type === "image" && (
        <div className="grid grid-cols-1 gap-2">
          {urls.map((item, index) => (
            <ImageItem
              key={`img-${(item as UploadedImage).id ?? index}-${index}`}
              item={item as UploadedImage}
              index={index}
              onRetry={handleRetry}
              onUpdate={handleUpdateImage}
            />
          ))}

          {urls.length < maxFiles && (
            <div
              className="flex flex-col items-center justify-center h-24 border-2 border-dashed border-slate-200 rounded-lg cursor-pointer hover:border-slate-300 hover:bg-slate-50 transition-all text-slate-400"
              onClick={() => {
                setRetryIndex(null);
                fileInputRef.current?.click();
              }}
            >
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] font-bold uppercase tracking-tighter">
                追加
              </span>
            </div>
          )}
        </div>
      )}

      {urls.length > 0 && type === "audio" && (
        <div className="space-y-2">
          {urls.map((item, index) => (
            <AudioItem
              key={`audio-${index}`}
              url={item as string}
              index={index}
              onRemove={handleRemove}
            />
          ))}

          {urls.length < maxFiles && (
            <Button
              variant="outline"
