type FolderStats = {
  dueCount: number;
  unlearnedCount: number;
  lastReviewedAt?: Date | string | null;
};

type FolderDashboardHandlers = {
  onStartStudy: () => void;
  onViewCards: () => void;
  onCreateCard: () => void;
};

