  reloadSyncSettings: () => Promise<void>;
  securityState: SecurityState;
  dismissSecurityAlert: (alertId: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
  currentUser: null,
  loading: true,
  syncStatus: "idle",
  syncNotice: "none",
  lastSyncTime: null,
  triggerSync: async () => {},
  // 高度化機能
  syncService: null,
  queueCount: 0,
  conflictCount: 0,
  reloadSyncSettings: async () => {},
  securityState: { isLocked: false, requires2FA: false, alerts: [] },
  dismissSecurityAlert: async () => {},
});

export function useAuth() {
  return useContext(AuthContext);
}

interface AuthProviderProps {
  children: ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [currentUser, setCurrentUser] = useState<FirebaseUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<
    "idle" | "syncing" | "success" | "error"
  >("idle");
  const [syncNotice, setSyncNotice] = useState<"none" | "wifi_wait">("none");
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [syncService, setSyncService] = useState<ISyncService | null>(null);

  // 高度化機能: キュー件数と競合件数
  const [queueCount, setQueueCount] = useState(0);
  const [conflictCount, setConflictCount] = useState(0);
  // セキュリティ状態
  const [securityState, setSecurityState] = useState<SecurityState>({
    isLocked: false,
    requires2FA: false,
    alerts: [],
  });
  const lastKnownUserIdRef = useRef<string | null>(null);

  const dismissSecurityAlert = useCallback(
    async (alertId: string) => {
      if (!syncService) return;
      await syncService.dismissSecurityAlert(alertId);
    },
    [syncService],
  );

  // 同期設定とインターバル管理用ref
  const syncIntervalRef = useRef<any | null>(null);
  const syncSettingsRef = useRef<SyncSettings | null>(null);

  /**
   * キュー件数と競合件数を更新
   */
  const updateCounts = useCallback(async () => {
    if (!syncService) return;
    try {
      const { pending: queue } = await syncService.getQueueStatus();
      const conflicts = await syncService.getUnresolvedConflicts();
      setQueueCount(queue);
      setConflictCount(conflicts.length);
    } catch (error) {
      console.error("[Auth] Failed to update counts:", error);
    }
  }, [syncService]);

  /**
   * 同期設定を再読み込みしてインターバルを再設定
   */
  const reloadSyncSettings = useCallback(async () => {
    // サービス側の個別ロードは廃止し、Factory経由で再取得
    if (!currentUser) return;

    try {
      const service = await SyncServiceFactory.getInstance(currentUser.uid);
      const settings = await service.loadSettings(); // Still need to load settings from the service
      syncSettingsRef.current = settings;

      // 既存のインターバルをクリア
      if (syncIntervalRef.current) {
        clearInterval(syncIntervalRef.current);
        syncIntervalRef.current = null;
      }

      // 自動同期が有効な場合、新しいインターバルを設定
      if (settings.autoSync && navigator.onLine) {
        const intervalMs = settings.intervalMinutes * 60 * 1000;
        console.log(
          `[Auth] Setting up auto-sync interval: ${settings.intervalMinutes} minutes`,
        );

        syncIntervalRef.current = setInterval(async () => {
          if (navigator.onLine && syncStatus !== "syncing") {
            console.log("[Auth] Running background sync...");
            await triggerSyncInternal("background"); // Pass 'background' for background sync
          }
        }, intervalMs);
      }
    } catch (error) {
      console.error("[Auth] Failed to reload sync settings:", error);
    }
  }, [currentUser, syncStatus]); // Added currentUser to dependencies

  /**
   * 内部同期トリガー（循環参照を避けるため分離）
   */
  const triggerSyncInternal = useCallback(
    async (source: SyncContextSource = "user_initiated") => {
      if (!syncService || !currentUser) {
        console.warn("[Auth] Cannot sync: No sync service or user");
        return;
      }

      setSyncStatus("syncing");
      setSyncNotice("none");
      try {
        // 旧 UI 互換のため、戻り値がある synchronize() を使用
        const result = await syncService.synchronize();
        const db = await getLocalDb();
        const currentLastSync = await db.getLastSyncTime(currentUser.uid);
        setLastSyncTime(currentLastSync);

        // WiFi限定モード等で「同期スキップ」の場合はエラー扱いしない
        const skippedByPolicy = result.errors.some((message) =>
          message.includes("WiFi限定モードのためスキップ"),
        );
        if (skippedByPolicy) {
          setSyncStatus(currentLastSync ? "success" : "idle");
          setSyncNotice("wifi_wait");
          await updateCounts();
          console.log("[Auth] Sync skipped by policy:", result);
          return;
        }
        setSyncNotice("none");

        // 競合がある場合は'error'状態（ユーザーの注意を引くため）
        if (result.conflicts > 0) {
          setSyncStatus("error");
        } else if (result.success) {
          setSyncStatus("success");
        } else {
          setSyncStatus("error");
        }

        // カウントを更新
        await updateCounts();

        console.log("[Auth] Sync completed:", result);
      } catch (error) {
        console.error("[Auth] Sync failed:", error);
        setSyncNotice("none");
        setSyncStatus("error");
      }
      // No finally needed here because all paths set status, but for safety against future changes:
      // If we wanted to guarantee exit from 'syncing', we could check in finally.
      // However, the explicit sets above covers it.
      // The user's issue might be in initialization.
    },
    [syncService, currentUser, updateCounts],
  );

  // Manual sync trigger function
  const triggerSync = useCallback(async () => {
    await triggerSyncInternal("user_initiated");
  }, [triggerSyncInternal]);

  useEffect(() => {
    let isInitialCall = true;
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      // ⚠ 初回以外は setLoading(true) を呼ばない。
      // 以前は毎回 setLoading(true) を呼んでいたため、BrowserRouter が
      // 破棄→再構築され、ルーティング状態が失われていた。
      // 初回のみ loading=true を維持し（初期値が true）、
      // 2回目以降（トークンリフレッシュ等）は loading を変えずに
      // バックグラウンドで処理する。
      if (isInitialCall) {
        isInitialCall = false;
        // loading は初期値 true のまま — 明示的に setLoading(true) する必要なし
      }
      // NOTE: 初回以外は loading を true にしない（UI フリーズ防止）
      if (user) {
        lastKnownUserIdRef.current = user.uid;
        try {
          // 1. Initialize user-specific DB
          await initializeDB(user.uid);

          // 🔥 2. ブラウザストレージ健全性チェック（Phase 1-3）
          // - IndexedDB の健全性チェック
          // - 異常検知 → 即破棄 → 再構築
          // - UI 描画前に完了を保証
          const { AppInitializer } = await import("../services/AppInitializer");
          const initResult = await AppInitializer.initialize(user.uid);
          if (initResult?.degraded) {
            console.warn("[Auth] startup_degraded=true", {
              userId: user.uid,
              reason: initResult.reason,
              skippedFailures: initResult.skippedFailures ?? 0,
            });
          }

          // 3. 同期サービス初期化 (非同期)
          const service = await SyncServiceFactory.getInstance(user.uid);
          setSyncService(service);

          // 4. 履歴とエラーのクリーンアップ（起動時に1回）
          const db = await getLocalDb();
          await db.cleanupSyncHistory();
          await db.cleanupSyncErrors();

          // [Auto-Fix] データ整合性の修復とオーナー権限の修正
          // エミュレータ⇄本番の切り替え時にデータの所有権を現ユーザーに統一し、同期対象にする
          console.log("[Auth] Running data integrity repair...");
          await db.repairDataIntegrity(user.uid);

          // 5. 同期設定を読み込み
          const settings = await service.loadSettings();
          syncSettingsRef.current = settings;

          const lastSync = await db.getLastSyncTime(user.uid);

          // 6. Decide sync strategy
          setSyncStatus("syncing");
          setSyncNotice("none");
          try {
            let skippedByPolicy = false;
            if (lastSync) {
              // Existing device, perform delta sync
              console.log(
                "[Auth] Existing user detected. Performing delta sync.",
              );
              // Note: synchronize() does not throw, it returns a result object.
              const result = await service.synchronize();
              skippedByPolicy = result.errors.some((message) =>
                message.includes("WiFi限定モードのためスキップ"),
              );
              if (skippedByPolicy) {
                console.log("[Auth] Initial sync skipped by policy:", result);
                setSyncNotice("wifi_wait");
              }
              // Status update handled below based on lastSyncTime presence
            } else {
              // New device or first login, perform full sync
              console.log(
                "[Auth] New user or device detected. Performing full sync.",
              );
              // Note: performFullSync() THROWS if it fails (e.g. download failure).
              await service.performFullSync();
            }

            // Initialization Success Path
            // Correctly fetch lastSyncTime from syncMetadata table
            const currentLastSync = await db.getLastSyncTime(user.uid);
            setLastSyncTime(currentLastSync);

            // 初回同期未実行の場合は 'idle'、実行済みの場合は 'success'
            // Explicitly set success if we have a timestamp, ensuring we exit 'syncing'
            setSyncStatus(currentLastSync ? "success" : "idle");
            if (!skippedByPolicy) {
              setSyncNotice("none");
            }

            // 7. カウントを更新
            const { pending: queue } = await service.getQueueStatus();
            const conflicts = await service.getUnresolvedConflicts();
            setQueueCount(queue);
            setConflictCount(conflicts.length);
          } catch (error) {
            // Initialization Failure Path (e.g. performFullSync threw error)
            console.error("[Auth] Synchronization failed during login:", error);

            // Strict Rule: If lastSyncTime is null (fresh install/user), do NOT set error state.
            // Remain 'idle' so UI shows "Not Executed".
            // If we had a lastSyncTime (previous success), then it's a regression/error.
            const existingLastSync = await db.getLastSyncTime(user.uid);
            // Strict logic: If we have a previous sync time, it's an error. If not, it's idle.
            setSyncStatus(existingLastSync ? "error" : "idle");
            setSyncNotice("none");
          }
        } catch (error) {
          // Outer catch for instantiation errors, handled same as sync failure
          console.error("[Auth] Fatal setup error:", error);
          setSyncNotice("none");
          setSyncStatus("error");
        } finally {
          setCurrentUser(user);
          setLoading(false);
        }
      } else {
        // User is logged out
        const previousUserId = lastKnownUserIdRef.current || undefined;
        try {
          // ログアウト時のDBリセットは best-effort
          await resetLocalDBForLogout(previousUserId);
          await initializeDB("anonymous");
        } catch (error) {
          console.warn("[Auth] Logout DB reset failed (non-fatal):", error);
        }
        SyncServiceFactory.resetInstance(previousUserId);
        lastKnownUserIdRef.current = null;
        setCurrentUser(null);
        setLoading(false);
        setSyncStatus("idle");
        setSyncNotice("none");
        setLastSyncTime(null);
        setSyncService(null);
        setQueueCount(0);
        setConflictCount(0);
        setSecurityState({ isLocked: false, requires2FA: false, alerts: [] });

        // インターバルをクリア
        if (syncIntervalRef.current) {
          clearInterval(syncIntervalRef.current);
          syncIntervalRef.current = null;
        }
      }
    });

    return unsubscribe;
  }, []);

  // 設定駆動型バックグラウンド同期 & セキュリティ監視
  useEffect(() => {
    if (!syncService || !currentUser) return;

    // 初回設定読み込みとインターバル設定
    reloadSyncSettings();

    // セキュリティ監視開始
    const stopMonitoring = syncService.monitorSecurity((newState) => {
      console.log("[Auth] Security state updated:", newState);
      setSecurityState(newState);

      // ロックされた場合はログアウトさせる？
      // 仕様としては「ロック画面表示」なので、ここではステート更新に留める
      // ただし、もし強制ログアウト要件があればここに追加
    });

    return () => {
      if (syncIntervalRef.current) {
        clearInterval(syncIntervalRef.current);
        syncIntervalRef.current = null;
      }
      stopMonitoring();
    };
  }, [syncService, currentUser, reloadSyncSettings]);

  // Sync when coming back online (キュー処理優先)
  useEffect(() => {
    const handleOnline = async () => {
      if (syncService && currentUser && syncStatus !== "syncing") {
        console.log(
          "[Auth] Network reconnected. Processing queue and syncing...",
        );

        // キュー処理を先に実行
        const queueResult = await syncService.processQueue();
        console.log(`[Auth] Queue processed: ${queueResult.processed} items`);

        // その後、通常の同期
        await triggerSync();
      }
    };

    window.addEventListener("online", handleOnline);
    return () => window.removeEventListener("online", handleOnline);
  }, [syncService, currentUser, syncStatus, triggerSync]);

  // 定期的にカウントを更新（5秒ごと）
  useEffect(() => {
    if (!syncService) return;

    const interval = setInterval(updateCounts, 5000);
    return () => clearInterval(interval);
  }, [syncService, updateCounts]);

  const value = {
    currentUser,
    loading,
    syncStatus,
    syncNotice,
    lastSyncTime,
    triggerSync,
    // 高度化機能
    syncService,
    queueCount,
    conflictCount,
    reloadSyncSettings,
    securityState,
    dismissSecurityAlert,
  };

  // Debug logging
  console.log({
    syncStatus,
    syncNotice,
    lastSyncTime,
    lastSyncError: null, // access not straightforward here, assuming handled by syncService internally
    totalSyncCount: 0, // transient, actual count in syncService. getSyncStats needed to verify
    queueCount,
    conflictCount,
  });

  // ⚠ 以前は {!loading && children} で children を条件レンダリングしていたが、
  // これにより BrowserRouter が loading 遷移のたびに破棄→再構築され、
  // React Router のルーティング状態が失われてリダイレクトが発生していた。
  // loading 状態のハンドリングは ProtectedRoute / AppContent に委譲する。
  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

import { useState, useMemo } from "react";
import { useLiveQuery } from "dexie-react-hooks";
import { getLocalDb } from "../services/localDB";
import { useAuth } from "../contexts/AuthContext";
import { normalizeCard } from "../utils";
import { normalizeMemoryStability } from "../utils/reviewUtils";
import { useUserSettings, DEFAULT_SETTINGS } from "./useUserSettings";
import type { Card } from "../types";
import { normalizeInkDocument } from "@/components/ink/inkTypes";
import {
  DEFAULT_LAYOUT_ROWS,
  normalizeLayoutRows,
} from "@/domain/card/extraRows";

// 空カード判定用のヘルパー関数（createCard と updateCard で共通利用）
function isCardDeleted(
  card: Partial<Card> & {
    is_deleted?: boolean;
    deleted?: boolean;
    deletedAt?: unknown;
    deleted_at?: unknown;
  },
) {
  const deletedAt = (card as any).deletedAt ?? (card as any).deleted_at;
  return Boolean(
    card.isDeleted ?? card.is_deleted ?? (card as any).deleted ?? deletedAt,
  );
}

function hasBlocksContent(blocks?: unknown[]): boolean {
  return (
    blocks?.some((b) => {
      if (b.type === "text") return b.content?.trim();
      if (b.type === "markdown") return b.markdown?.trim();
      if (b.type === "code") return b.code?.code?.trim();
      if (b.type === "image") return b.images?.length > 0;
      if (b.type === "audio") return b.audios?.length > 0;
      if (b.type === "math") return b.math?.latex?.trim();
      if (b.type === "reference")
        return b.references?.some((r: unknown) => r.url?.trim());
      return false;
    }) || false
  );
}

export function useCards(folderId?: string) {
  const { currentUser } = useAuth();
  const [error] = useState<string | null>(null);

  // Use settings to determine init schedule
  const { settings } = useUserSettings();

  // useLiveQueryでリアクティブにカードを取得
  const rawCards = useLiveQuery(
    async () => {
      try {
        if (!currentUser) return [];
        const db = await getLocalDb(currentUser.uid);
        const all = await db.getAllCards();
        return all;
      } catch (err: unknown) {
        console.error(`[useCards] Error: ${err.message}`);
        return [];
      }
    },

    [currentUser?.uid], // localDb.name is removed as dependency because it's now internal to liveQuery
  );

  // ... (rest of the hook code, I'll use multi_replace for accuracy if needed, but let's try one big block or smaller chunks)
  // Actually, I'll do specific chunks for safety.

  // 正規化・フィルタ・ソートはuseMemoで処理
  const cards = useMemo(() => {
    if (!rawCards || rawCards.length === 0) return [];

    let normalized = rawCards.map(normalizeCard);

    // 削除済み（legacy is_deleted 含む）を除外
    normalized = normalized.filter(
      (c) => !isCardDeleted(c as Partial<Card> & { is_deleted?: boolean }),
    );

    // folderId でfilter
    if (folderId) {
      normalized = normalized.filter((c) => c.folderId === folderId);
    }

    // orderIndex でソート
    normalized.sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));

    return normalized;
  }, [rawCards, folderId]);

  // useLiveQueryはundefinedを返すことがあるのでloadingを判定
  const loading = rawCards === undefined;

  const createCard = async (cardData: Partial<Card>) => {
    if (!currentUser) throw new Error("認証が必要です");

    // Validation: カードが完全に空（タイトルもコンテンツもタグもない）場合は保存を拒否
    const hasBlocksContent = (blocks?: unknown[]) => {
      return (
        blocks?.some((b) => {
          if (b.type === "text") return b.content?.trim();
          if (b.type === "markdown") return b.markdown?.trim();
          if (b.type === "code") return b.code?.code?.trim();
          if (b.type === "image") return b.images?.length > 0;
          if (b.type === "audio") return b.audios?.length > 0;
          if (b.type === "math") return b.math?.latex?.trim();
          if (b.type === "reference")
            return b.references?.some((r: unknown) => r.url?.trim());
          return false;
        }) || false
      );
    };

    const isCompletelyEmpty =
      !cardData.title?.trim() &&
      !(Array.isArray(cardData.tagIds) && cardData.tagIds.length > 0) &&
      !cardData.tags?.length &&
      !hasBlocksContent(cardData.questionBlocks) &&
      !hasBlocksContent(cardData.answerBlocks) &&
      !cardData.questionText?.trim() && // Legacy support
      !cardData.answerText?.trim(); // Legacy support

    // 新規作成時はタイトルが空であることを許容する（あとで編集するため）
    // そのため、作成時のバリデーションはスキップする
    /*
    if (isCompletelyEmpty) {
      console.error('[useCards] Refusing to create completely empty card');
      throw new Error('カードの内容を入力してください。');
    }
    */

    // Force fetch settings to ensure freshness
    const db = await getLocalDb(currentUser.uid);
    const userSettings = await db.userSettings.get(currentUser.uid);
    const effectiveSettings = { ...DEFAULT_SETTINGS, ...(userSettings || {}) };
    const startNextDay = effectiveSettings.reviewStartNextDay ?? true;

    const now = new Date();
    // orderIndex: 既存カードとの競合を避け、時間軸での並びを保証するタイムスタンプベース
    const orderIndex =
      cardData.orderIndex ??
      Date.now() * 10000 + Math.floor(Math.random() * 10000);

    // 表示用のQ番号は既存のカード数+1とする（orderIndexが巨大な数値になるため）
    const folderCards = cards.filter(
      (c) => c.folderId === (cardData.folderId || ""),
    );
    const questionNumber =
      cardData.questionNumber ?? `Q${folderCards.length + 1}`;
    const id = crypto.randomUUID();

    const nextReviewDate = (() => {
      // If manually set, use it
      if (cardData.nextReviewDate) return cardData.nextReviewDate;

      const d = new Date(now);
      if (startNextDay) {
        d.setDate(d.getDate() + 1); // Schedule for tomorrow
      }
      d.setHours(0, 0, 0, 0);
      return d;
    })();

    const normalizedReviewLogs = Array.isArray(cardData.reviewLogs)
      ? [...cardData.reviewLogs].sort(
          (a, b) =>
            new Date(a.reviewedAt).getTime() - new Date(b.reviewedAt).getTime(),
        )
      : [];

    const newCard: Card = {
      id,
      userId: currentUser.uid,
      deviceId: cardData.deviceId || "web",
      folderId: cardData.folderId || "",
      orderIndex,
      questionNumber,
      title: cardData.title || "",
      isDraft: cardData.isDraft ?? false,
      // 新規作成時は必ず isDeleted: false で保存
      isDeleted: false,
      hasUncertainty: cardData.hasUncertainty ?? false,
      isBookmarked: cardData.isBookmarked ?? false,
      isCompleted: cardData.isCompleted ?? false,
      isSilent: cardData.isSilent ?? false,
      questionText: cardData.questionText || "",
      questionImages: cardData.questionImages || [],
      questionAudios: cardData.questionAudios || [],
      questionCode: cardData.questionCode || null,
      questionMarked: cardData.questionMarked || "",
      answerText: cardData.answerText || "",
      answerImages: cardData.answerImages || [],
      answerAudios: cardData.answerAudios || [],
      answerCode: cardData.answerCode || null,
      answerMarked: cardData.answerMarked || "",
      // Ensure blocks are carried over from cardData
      questionBlocks: cardData.questionBlocks || [],
      answerBlocks: cardData.answerBlocks || [],
      layoutRows: normalizeLayoutRows(
        (cardData as any).layoutRows ??
          (cardData as any).layout_rows ??
          DEFAULT_LAYOUT_ROWS,
      ),
      inkQuestion: normalizeInkDocument(cardData.inkQuestion),
      inkAnswer: normalizeInkDocument(cardData.inkAnswer),
      memoryStability: 0,
      currentLevel: cardData.currentLevel ?? null,
      nextReviewDate,
      createdAt: now,
      updatedAt: now,
      ...(Array.isArray(cardData.tagIds)
        ? { tagIds: cardData.tagIds }
        : Array.isArray(cardData.tags)
          ? { tags: cardData.tags }
          : {}),
      reviewLogs: normalizedReviewLogs,
    };

    try {
      const db = await getLocalDb(currentUser.uid);
      await db.addItem("cards", newCard);
      return newCard;
    } catch (err) {
      console.error("[createCard] ERROR during LocalDB add", {
        table: "cards",
        cardId: newCard.id,
        error: err,
      });
      throw err;
    }
  };

  const updateCard = async (id: string, data: Partial<Card>) => {
    if (!currentUser) throw new Error("認証が必要です");

    const db = await getLocalDb(currentUser.uid);

    // 更新後のカード状態をシミュレーション
    const currentCard = cards.find((c) => c.id === id);
    if (!currentCard) {
      console.warn("[updateCard] Card not found:", id);
      return;
    }

    const mergedCard = { ...currentCard, ...data };
    const patch: Partial<Card> = { ...data };
    // Legacy rows fields are read-only migration inputs. Never persist them again.
    delete (patch as any).questionExtraRows;
    delete (patch as any).answerExtraRows;
    delete (patch as any).question_extra_rows;
    delete (patch as any).answer_extra_rows;
    if (Array.isArray(patch.reviewLogs)) {
      patch.reviewLogs = [...patch.reviewLogs].sort(
        (a, b) =>
          new Date(a.reviewedAt).getTime() - new Date(b.reviewedAt).getTime(),
      );
    }
    if (Array.isArray(patch.tagIds)) {
      delete (patch as Partial<Card> & { tags?: unknown }).tags;
    }

    // 通常の更新処理
    await db.updateItem("cards", id, {
      ...patch,
      updatedAt: new Date(),
    });
  };

  const deleteCard = async (id: string) => {
    if (!currentUser) throw new Error("認証が必要です");
    // ソフト削除: ACTIVE → TRASHED
    // isDeleted と deletedAt を同時に設定
    const db = await getLocalDb(currentUser.uid);
    await db.softDelete("cards", id);
  };

  const toggleFlag = async (
    id: string,
    flag: "hasUncertainty" | "isCompleted" | "isSilent" | "isBookmarked",
  ) => {
    const card = cards.find((c) => c.id === id);
    if (!card) return;

    await updateCard(id, { [flag]: !card[flag] });
  };

  /**
   * カードを別フォルダへ移動
   * - folderId を更新
   * - 移動先フォルダの末尾に追加（orderIndex を最大値+1に設定）
   */
  const moveCardToFolder = async (cardId: string, targetFolderId: string) => {
    if (!currentUser) throw new Error("認証が必要です");

    const db = await getLocalDb(currentUser.uid);

    // 移動先フォルダ内の最大 orderIndex を取得
    const allCards = await db.getAllCards();
    const targetFolderCards = allCards.filter(
      (c) =>
        c.folderId === targetFolderId &&
        !isCardDeleted(c as Partial<Card> & { is_deleted?: boolean }),
    );
    const maxOrderIndex = targetFolderCards.reduce(
      (max, c) => Math.max(max, c.orderIndex || 0),
      0,
    );

    // カードを更新
    await db.updateItem("cards", cardId, {
      folderId: targetFolderId,
      orderIndex: maxOrderIndex + 1,
      updatedAt: new Date(),
    });
  };

  /**
   * フォルダ内のカードを並び替え
   * - cardIds の順序で orderIndex を 0, 1, 2, ... n-1 に振り直す
   */
  const reorderCards = async (folderId: string, cardIds: string[]) => {
    if (!currentUser) throw new Error("認証が必要です");

    const db = await getLocalDb(currentUser.uid);

    // 各カードの orderIndex を更新
    const updates = cardIds.map((cardId, index) =>
      db.updateItem("cards", cardId, {
        orderIndex: index,
        updatedAt: new Date(),
      }),
    );

    await Promise.all(updates);
  };

  return {
    cards,
    loading,
    error,
    createCard,
    updateCard,
    deleteCard,
    toggleFlag,
    moveCardToFolder,
    reorderCards,
  };
}

import { useState, useMemo, useCallback } from "react";
import { useLiveQuery } from "dexie-react-hooks";
import { getLocalDb } from "../services/localDB";
import { useAuth } from "../contexts/AuthContext";
import type { Document, DocumentItem } from "../types";

/**
 * PDFドキュメントを取得・管理するためのフック
 */
export function useDocuments(folderId?: string) {
  const { currentUser } = useAuth();
  const [error, setError] = useState<string | null>(null);

  // useLiveQueryでドキュメントを取得
  const rawDocuments = useLiveQuery(async () => {
    try {
      if (!currentUser) return [];
      const db = await getLocalDb(currentUser.uid);
      // documentsテーブルから全件取得
      const all = await db.documents.toArray();
      return all;
    } catch (err: unknown) {
      console.error(`[useDocuments] Error: ${err.message}`);
      setError(err.message);
      return [];
    }
  }, [currentUser]);

  // フィルタリングとソート
  const documents = useMemo(() => {
    if (!rawDocuments) return [];

    let filtered = rawDocuments.filter(
      (d) => !(d.isDeleted ?? (d as any).is_deleted),
    );

    if (folderId) {
      filtered = filtered.filter((d) => d.folderId === folderId);
    }

    // orderIndexでソート
    return filtered.sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));
  }, [rawDocuments, folderId]);

  const loading = rawDocuments === undefined;

  // ドキュメント更新
  // ✅ スパース更新（必要なフィールドのみ更新）
  // viewerState など表示状態の更新時に、他のフィールドを上書きしない
  const updateDocument = useCallback(
    async (
      documentId: string,
      updates: Partial<DocumentItem>,
    ): Promise<void> => {
      if (!currentUser) throw new Error("User not authenticated");
      try {
        const db = await getLocalDb(currentUser.uid);
        const now = new Date();
        // ✅ db.documents.update() は Dexie のマージ更新
        // 指定されたフィールドのみ更新され、他のフィールドは保持される
        await db.documents.update(documentId, {
          ...updates,
          updatedAt: now,
          deviceId: currentUser.uid, // 簡略版（実装に応じて調整）
        });
      } catch (err: unknown) {
        console.error(`[useDocuments] Update error: ${err.message}`, {
          documentId,
          updates,
        });
        throw err;
      }
    },
    [currentUser],
  );

  return {
    documents,
    loading,
    error,
    updateDocument,
  };
}

import { useMemo } from "react";
import type { Card } from "@/types";
import { useUserSettings } from "@/hooks/useUserSettings";

export interface FolderStats {
  dueCount: number;
  unlearnedCount: number;
  lastReviewedAt: Date | null;
}

const toDate = (value: unknown): Date | null => {
  if (value === null || value === undefined) return null;
  if (typeof value?.toDate === "function") {
    const d = value.toDate();
    return d instanceof Date && !isNaN(d.getTime()) ? d : null;
  }
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value;
  if (typeof value === "number") {
    const d = new Date(value);
    return isNaN(d.getTime()) ? null : d;
  }
  if (typeof value === "string") {
    const d = new Date(value);
    return isNaN(d.getTime()) ? null : d;
  }
  return null;
};

export function useFolderStats(cards: Card[]): FolderStats {
  const { settings } = useUserSettings();

  return useMemo(() => {
    const autoCarryOver = settings?.autoCarryOver ?? true;
    const today = new Date();
    // Reset time components for accurate date comparison
    const tDate = new Date(
      today.getFullYear(),
      today.getMonth(),
      today.getDate(),
    );

    let dueCount = 0;
    let unlearnedCount = 0;
    let lastReviewedAt: Date | null = null;

    for (const card of cards) {
      // Skip deleted cards
      if (card.isDeleted || (card as any).is_deleted) continue;

      const isDraft = card.isDraft ?? (card as any).is_draft;

      // Calculate due cards
      if (!isDraft) {
        const reviewDate = toDate(
          card.nextReviewDate ?? (card as any).next_review_date,
        );
        if (reviewDate) {
          const rDate = new Date(
            reviewDate.getFullYear(),
            reviewDate.getMonth(),
            reviewDate.getDate(),
          );
          if (
            autoCarryOver ? rDate <= tDate : rDate.getTime() === tDate.getTime()
          ) {
            dueCount += 1;
          }
        }
      }

      // Calculate unlearned cards
      const reviewCount = card.reviewCount ?? (card as any).review_count ?? 0;
      if (!isDraft && reviewCount === 0) {
        unlearnedCount += 1;
      }

      // Track last review date
      const lastReview = toDate(
        card.lastReviewAt ?? (card as any).last_review_at,
      );
      if (lastReview && (!lastReviewedAt || lastReview > lastReviewedAt)) {
        lastReviewedAt = lastReview;
      }
    }

    return {
      dueCount,
      unlearnedCount,
      lastReviewedAt,
    };
  }, [cards, settings?.autoCarryOver]);
}

import { useLiveQuery } from "dexie-react-hooks";
import { Timestamp } from "firebase/firestore";
import { nanoid } from "nanoid";
import { getLocalDb } from "../services/localDB";
import { useAuth } from "../contexts/AuthContext";
import type { Folder } from "../types";
import { normalizeFolder } from "../utils";

export function useFolders() {
  const { currentUser } = useAuth();

  const folders = useLiveQuery(async () => {
    if (!currentUser) return [];
    const db = await getLocalDb();
    const rawFolders = await db.folders.toArray();

    const filtered = rawFolders.filter(
      (f) => !((f as any).isDeleted ?? (f as any).is_deleted),
    );

    return filtered.map(normalizeFolder);
  }, [currentUser?.uid]);

  const createFolder = async (
    name: string,
    parentId: string | null = null,
    color?: string,
    cloudSyncEnabled: boolean = true,
  ) => {
    if (!currentUser) throw new Error("認証が必要です");

    const db = await getLocalDb();

    // orderIndexの設定
    const currentFolders = folders || [];
    const siblings = currentFolders.filter(
      (f) => f.parentFolderId === parentId,
    );
    const orderIndex = siblings.length;

    const now = Timestamp.now();
    const folderData = {
      userId: currentUser.uid,
      folderName: name,
      parentFolderId: parentId,
      isDeleted: false,
      folderColor: color || null,
      cloudSyncEnabled,
      orderIndex,
      createdAt: now,
      updatedAt: now,
    };

    // 1. ローカル側で一意IDを生成（Firestore オブジェクトを誤って渡すバグ回避）
    const folderId =
      typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
        ? crypto.randomUUID()
        : nanoid();

    // 2. LocalDBへ書き込み (Local First & Sync Queued)
    const localData = {
      ...folderData,
      id: folderId,
      folderId: folderId, // Ensure consistency
      createdAt: now.toDate(),
      updatedAt: now.toDate(),
    };
    try {
      await db.addItem("folders", localData as any);
      return folderId;
    } catch (err) {
      console.error("[createFolder] ERROR during LocalDB add", {
        table: "folders",
        folderId,
        error: err,
      });
      throw err;
    }
  };

  const updateFolder = async (folderId: string, data: Partial<Folder>) => {
    if (!currentUser) throw new Error("認証が必要です");

    const now = Timestamp.now();
    const payload = {
      ...data,
      updatedAt: now.toDate(),
    };

    // 1. LocalDB更新 (Local First & Sync Queued)
    const db = await getLocalDb();
    await db.updateItem("folders", folderId, payload);
  };

  const reorderFolders = async (
    folderIds: string[],
    parentId: string | null = null,
  ) => {
    if (!currentUser) throw new Error("認証が必要です");

    const now = Timestamp.now();

    // 1. LocalDB Updates (Sync Queued for each)
    const db = await getLocalDb();
    const updates = folderIds.map((folderId, index) => {
      return db.updateItem("folders", folderId, {
        orderIndex: index,
        updatedAt: now.toDate(),
      });
    });
    await Promise.all(updates);
  };

  const deleteFolder = async (folderId: string) => {
    if (!currentUser) throw new Error("認証が必要です");

    const now = Timestamp.now();
    // 1. LocalDB softDelete (Sync Queued)
    const db = await getLocalDb();
    await db.softDelete("folders", folderId);

    // Recursive delete
    const currentFolders = folders || [];
    const subfolders = currentFolders.filter(
      (f) => f.parentFolderId === folderId,
    );
    for (const subfolder of subfolders) {
      await deleteFolder(subfolder.id);
    }
  };

  const getFolderTree = () => {
    const currentFolders = folders || [];
    const buildTree = (
      parentId: string | null,
    ): (Folder & { children: Folder[] })[] => {
      return currentFolders
        .filter((f) => f.parentFolderId === parentId)
        .sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0))
        .map((folder) => ({
          ...folder,
          children: buildTree(folder.folderId),
        }));
    };
    return buildTree(null);
  };

  return {
    folders: folders || [],
    loading: folders === undefined,
    error: null,
    createFolder,
    updateFolder,
    deleteFolder,
    reorderFolders,
    getFolderTree,
  };
}

import { useEffect, useRef, useState } from "react";
import {
  forceSimulation,
  forceLink,
  forceManyBody,
  forceCenter,
  forceCollide,
  type Simulation,
  type SimulationNodeDatum,
  type SimulationLinkDatum,
  type ForceLink,
} from "d3-force";

export interface GraphNode extends SimulationNodeDatum {
  id: string;
  type: "card" | "symbol";
  // Add other properties as needed
}

export interface GraphLink extends SimulationLinkDatum<GraphNode> {
  source: string | GraphNode;
  target: string | GraphNode;
  id?: string;
  lineType?: "straight" | "wave" | "zigzag" | "double";
}

interface UseGraphSimulationProps {
  nodes: GraphNode[];
  links: GraphLink[];
  width: number;
  height: number;
  centerForceStrength?: number;
  chargeStrength?: number;
  linkDistance?: number;
}

export function useGraphSimulation({
  nodes,
  links,
  width,
  height,
  centerForceStrength = 1,
  chargeStrength = -300,
  linkDistance = 50,
}: UseGraphSimulationProps) {
  const simulation = useRef<Simulation<GraphNode, GraphLink>>(null);
  const [currentNodes, setCurrentNodes] = useState<GraphNode[]>(nodes);
  const [currentLinks, setCurrentLinks] = useState<GraphLink[]>(links);

  useEffect(() => {
    // Initialize simulation
    const sim = forceSimulation<GraphNode, GraphLink>(nodes)
      .force(
        "link",
        forceLink<GraphNode, GraphLink>(links)
          .id((d) => d.id)
          .distance(linkDistance),
      )
      .force("charge", forceManyBody().strength(chargeStrength))
      .force(
        "center",
        forceCenter(width / 2, height / 2).strength(centerForceStrength),
      )
      .force("collide", forceCollide().radius(50)) // Prevent overlap, based on card size
      .on("tick", () => {
        // Update state to trigger re-render on tick
        // Optimization: Maybe don't set state on every tick if performance is an issue
        // Instead, update a ref or use a mutable store, or use requestAnimationFrame
        // For React state, throttling might be needed.
        // For now, simple state update (works fine for small graphs)
        setCurrentNodes([...nodes]);
        setCurrentLinks([...links]);
      });

    simulation.current = sim;

    return () => {
      sim.stop();
    };
  }, []); // Run once on mount? Or when nodes/links change?

  // Handle updates to nodes/links efficiently
  useEffect(() => {
    if (!simulation.current) return;

    const sim = simulation.current;

    // Update nodes
    sim.nodes(nodes);

    // Update links
    // Update links
    const linkForce = sim.force("link") as ForceLink<GraphNode, GraphLink>;
    if (linkForce) {
      linkForce.links(links).distance(linkDistance);
    }

    sim.alpha(1).restart();
  }, [
    nodes,
    links,
    width,
    height,
    chargeStrength,
    centerForceStrength,
    linkDistance,
  ]);

  const restart = () => {
    if (simulation.current) {
      simulation.current.alpha(1).restart();
    }
  };
  const getSimulation = () => simulation.current;

  return {
    nodes: currentNodes,
    links: currentLinks,
    getSimulation,
    restart,
  };
}

