   * 通信量の比較
   *
   * 全同期方式とCRDT差分方式の通信量を比較
   */
  compareDataSize(fullData: CardData[]): {
    fullSyncSize: number;
    deltaSize: number;
    reduction: number;
  } {
    // 全同期のサイズ（JSON文字列化）
    const fullSyncSize = JSON.stringify(fullData).length;

    // CRDT差分のサイズ
    const delta = this.getDelta();
    const deltaSize = delta.length;

    // 削減率
    const reduction = ((fullSyncSize - deltaSize) / fullSyncSize) * 100;

    console.log(`[CRDT] Data size comparison:`, {
      fullSyncSize: `${fullSyncSize} bytes`,
      deltaSize: `${deltaSize} bytes`,
      reduction: `${reduction.toFixed(1)}%`,
    });

    return {
      fullSyncSize,
      deltaSize,
      reduction,
    };
  }

  /**
   * Y.Docの状態をリセット
   */
  reset(): void {
    this.ydoc.destroy();
    this.ydoc = new Y.Doc();
    this.cards = this.ydoc.getMap("cards");
  }
}

import { storage, firestoreDb as db } from "./firebase";
import { ref, uploadBytes, getDownloadURL } from "firebase/storage";
import { doc, updateDoc, arrayUnion } from "firebase/firestore";
import { getLocalDb, type LocalDBLike } from "./localDB";
import type { UploadedImage } from "../types";
import { createStorageUrl } from "../types/branded";

const MAX_QUOTA = 500 * 1024 * 1024; // 500MB
const MAX_RETRIES = 5;

export class ImageSyncService {
  private localDB: LocalDBLike;

  constructor(userId: string, localDB: LocalDBLike) {
    this.localDB = localDB;
  }

  private async getStorageUsage(): Promise<number> {
    const stats =
      (await this.localDB.userStats.get("current")) ||
      (await this.localDB.userStats.toCollection().first());
    return stats?.totalStorageUsedBytes || 0;
  }

  private async checkQuota(fileSize: number): Promise<boolean> {
    const currentUsage = await this.getStorageUsage();
    return currentUsage + fileSize <= MAX_QUOTA;
  }

  private sleep(ms: number) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private async calculateChecksum(blob: Blob): Promise<string> {
    const arrayBuffer = await blob.arrayBuffer();
    const hashBuffer = await crypto.subtle.digest("SHA-256", arrayBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map((b) => b.toString(16).padStart(2, "0")).join("");
  }

  /**
   * サムネイルを生成する（Canvasを使用）
   */
  async generateThumbnail(
    blob: Blob,
    maxWidth = 300,
    maxHeight = 300,
  ): Promise<Blob> {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        let width = img.width;
        let height = img.height;

        if (width > maxWidth || height > maxHeight) {
          const ratio = Math.min(maxWidth / width, maxHeight / height);
          width *= ratio;
          height *= ratio;
        }

        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext("2d");
        if (!ctx) {
          reject(new Error("Failed to get canvas context"));
          return;
        }

        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob(
          (thumbnailBlob) => {
            if (thumbnailBlob) {
              resolve(thumbnailBlob);
            } else {
              reject(new Error("Failed to create thumbnail blob"));
            }
          },
          "image/jpeg",
          0.7,
        );
      };
      img.onerror = () => reject(new Error("Failed to load image"));
      img.src = URL.createObjectURL(blob);
    });
  }

  /**
   * ローカルにのみ存在する（remoteUrlがない）画像を検出し、Storageにアップロードする
   */
  async syncLocalImages(
    userId: string,
    onProgress?: (msg: string) => void,
  ): Promise<void> {
    console.log("[ImageSync] Starting image sync check...");
    onProgress?.("画像同期の準備中...");
    const cards = await this.localDB.cards.toArray();

    for (const card of cards) {
      const updatedQuestionImages = await this.processImageArray(
        userId,
        card.id,
        "cards",
        "questionImages",
        card.questionImages,
        onProgress,
      );
      const updatedAnswerImages = await this.processImageArray(
        userId,
        card.id,
        "cards",
        "answerImages",
        card.answerImages,
        onProgress,
      );

      if (updatedQuestionImages || updatedAnswerImages) {
        await this.localDB.cards.update(card.id, {
          questionImages: updatedQuestionImages || card.questionImages,
          answerImages: updatedAnswerImages || card.answerImages,
          updatedAt: new Date(),
        });
      }
    }
  }

  private async processImageArray(
    userId: string,
    entityId: string,
    table: string,
    fieldName: string,
    images: UploadedImage[],
    onProgress?: (msg: string) => void,
  ): Promise<UploadedImage[] | null> {
    if (!images || images.length === 0) return null;
    let changed = false;
    const newImages = [...images];

    for (let i = 0; i < newImages.length; i++) {
      const image = newImages[i];
      // localUrlがあり、remoteUrlがない場合
      if (image.localUrl && !image.remoteUrl) {
        // すでに完了しているか、直近で失敗しすぎていないか確認
        if (image.uploadState === "completed") continue;

        try {
          onProgress?.(
            `アップロード中 (${i + 1}/${newImages.length}): ${image.id.substring(0, 8)}...`,
          );
          const syncedImage = await this.uploadImageToStorage(userId, image);
          newImages[i] = syncedImage;
          changed = true;
          console.log(`[ImageSync] Successfully uploaded image ${image.id}`);
        } catch (error) {
          console.error(
            `[ImageSync] Failed to upload image ${image.id}:`,
            error,
          );
          newImages[i] = {
            ...image,
            uploadState: "failed",
            lastAttempt: new Date(),
          };
          changed = true;
        }
      }
    }

    return changed ? newImages : null;
  }

  private async uploadImageToStorage(
    userId: string,
    image: UploadedImage,
  ): Promise<UploadedImage> {
    if (!image.localUrl) throw new Error("Local URL missing");

    const response = await fetch(image.localUrl);
    const blob = await response.blob();

    // 1. Quota Check
    const thumbnailBlob = await this.generateThumbnail(blob);
    const totalSize = blob.size + thumbnailBlob.size;

    // Checksum
    const checksum = await this.calculateChecksum(blob);

    // 2. Check if already uploaded (Resume / Deduplication)
    // 実装プランに基づき、同一チェックサムの画像がクラウドにあれば再利用可能
    const highResPath = `users/${userId}/images/${checksum}_full`;
    const highResRef = ref(storage, highResPath);

    try {
      const existingUrl = await getDownloadURL(highResRef);
      console.log(
        `[ImageSync] Image with checksum ${checksum} already exists. Skipping upload.`,
      );

      const thumbPath = `users/${userId}/images/${checksum}_thumb`;
      const thumbUrl = await getDownloadURL(ref(storage, thumbPath));

      return {
        ...image,
        remoteUrl: createStorageUrl(existingUrl),
        thumbnailUrl: createStorageUrl(thumbUrl),
        remoteId: image.id,
        storagePath: highResPath,
        status: "ready",
        uploadState: "completed",
        sizeBytes: blob.size,
        checksum: checksum,
        lastAttempt: new Date(),
      };
    } catch (e) {
      // Not found, proceed with upload
    }

    if (!(await this.checkQuota(totalSize))) {
      throw new Error("Storage quota exceeded (Max 500MB)");
    }

    let lastError: unknown = null;
    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        // Update state to inProgress
        const inProgressImage = {
          ...image,
          uploadState: "inProgress" as const,
          lastAttempt: new Date(),
          checksum: checksum,
        };

        // 1. 高解像度版のアップロード
        const highResPath = `users/${userId}/images/${image.id}_full`;
        const highResRef = ref(storage, highResPath);
        await uploadBytes(highResRef, blob);
        const highResUrl = await getDownloadURL(highResRef);

        // 2. サムネイルのアップロード
        const thumbnailPath = `users/${userId}/images/${image.id}_thumb`;
        const thumbnailRef = ref(storage, thumbnailPath);
        await uploadBytes(thumbnailRef, thumbnailBlob);
        const thumbnailUrl = await getDownloadURL(thumbnailRef);

        // Update UserStats usage
        await this.updateStorageUsage(blob.size, thumbnailBlob.size);

        return {
          ...image,
          remoteUrl: createStorageUrl(highResUrl),
          thumbnailUrl: createStorageUrl(thumbnailUrl),
          remoteId: image.id,
          storagePath: highResPath,
          status: "ready",
          uploadState: "completed",
          sizeBytes: blob.size,
          checksum: checksum,
          lastAttempt: new Date(),
        };
      } catch (error) {
        lastError = error;
        console.warn(
          `[ImageSync] Upload attempt ${attempt + 1} failed for ${image.id}:`,
          error,
        );
        if (attempt < MAX_RETRIES - 1) {
          await this.sleep(Math.pow(2, attempt) * 1000); // Exponential backoff
        }
      }
    }

    throw lastError || new Error("Upload failed after max retries");
  }

  private async updateStorageUsage(
    highResSize: number,
    thumbnailSize: number,
  ): Promise<void> {
    const statsTable = this.localDB.userStats;
    const stats =
      (await statsTable.get("current")) ||
      (await statsTable.toCollection().first());

    if (stats) {
      await statsTable.update(stats.id, {
        totalHighResBytes: (stats.totalHighResBytes || 0) + highResSize,
        totalThumbnailBytes: (stats.totalThumbnailBytes || 0) + thumbnailSize,
        totalStorageUsedBytes:
          (stats.totalStorageUsedBytes || 0) + highResSize + thumbnailSize,
        updatedAt: new Date(),
      });
    }
  }

  /**
   * [DEPRECATED/REMOVED]
   * Previously used to download images to creating local blobs.
   * Removed to prevent "Not allowed to load local resource" errors and blob leaks.
   * We now rely on standard browser caching for remote URLs.
   */
  async downloadHighResImage(image: UploadedImage): Promise<string | null> {
    return null;
  }
}

import type { ICloudSyncAdapter } from "../interfaces/ISyncService";
import { firestoreDb } from "../firebase";
import {
  collection,
  query,
  where,
  orderBy,
  limit,
  getDocs,
  writeBatch,
  doc,
  getDoc,
  Timestamp,
} from "firebase/firestore";
import * as Firestore from "firebase/firestore";
import { sanitizeBlobUrlsDeep } from "@/utils/blobUrlSanitizer";
import { sanitizeForLog } from "@/utils/logSanitizer";

/**
 * undefined は Firestore に投げた瞬間に爆発するので、深い階層まで除去する。
 * ※ 配列内の undefined も消す（Firestore 的にアウト）
 * ※ Date / Timestamp はそのまま
 */
function deepStripUndefined(input: unknown): unknown {
  if (input === undefined) return undefined;
  if (input === null) return null;

  if (input instanceof Timestamp) return input;
  if (input instanceof Date) return input;

  if (Array.isArray(input)) {
    return input.map(deepStripUndefined).filter((v) => v !== undefined);
  }

  if (typeof input === "object") {
    const out: unknown = {};
    for (const [k, v] of Object.entries(input)) {
      const cleaned = deepStripUndefined(v);
      if (cleaned !== undefined) out[k] = cleaned;
    }
    return out;
  }

  return input;
}

/**
 * serverTimestamp が使える環境なら使う。無理ならクライアント時刻で妥協。
 * （大規模運用なら最終的には serverTimestamp に統一したいが、まず死なないのが最優先）
 */
function cloudUpdatedAt(): unknown {
  const fn = (Firestore as any).serverTimestamp;
  if (typeof fn === "function") return fn();
  return Timestamp.now();
}

const COLLECTION_BY_TYPE: Record<string, string> = {
  card: "cards",
  folder: "folders",
  userSetting: "userSettings",
};

/**
 * Firestore writeBatch は「1リクエストあたり 10MiB」制限がある。
 * 大きい変更が混ざると commit が普通に死ぬので、サイズでチャンクして複数回 commit する。
 * （余裕を見て 7.5MiB 目安）
 */
const MAX_BATCH_BYTES = Math.floor(7.5 * 1024 * 1024);
/**
 * Firestore batch の最大書き込み数は 500。余裕を見て 450。
 */
const MAX_BATCH_OPS = 450;
/**
 * pullDiff のページサイズ（無限 getDocs で死なないように）
 */
const PAGE_SIZE = 500;

const _encoder = new TextEncoder();

/** JSON stringify の byte 数で概算（正確じゃないが爆死回避には十分） */
function estimateBytes(value: unknown): number {
  try {
    return _encoder.encode(JSON.stringify(value)).length;
  } catch {
    // stringify 不能 = だいたい危険なので大きめに見積もる
    return 1024 * 1024;
  }
}

function chunkChangesBySize(changes: unknown[]): unknown[][] {
  const chunks: unknown[][] = [];
  let current: unknown[] = [];
  let bytes = 0;

  for (const ch of changes) {
    // data だけじゃなく type/id も少し上乗せ
    const docBytes = estimateBytes(ch?.data ?? {});
    const extra = docBytes + 512;

    const wouldExceedBytes =
      current.length > 0 && bytes + extra > MAX_BATCH_BYTES;
    const wouldExceedOps =
      current.length > 0 && current.length + 1 > MAX_BATCH_OPS;

    if (wouldExceedBytes || wouldExceedOps) {
      chunks.push(current);
      current = [];
      bytes = 0;
    }

    current.push(ch);
    bytes += extra;
  }

  if (current.length > 0) chunks.push(current);
  return chunks;
}

export class CloudSyncAdapter implements ICloudSyncAdapter {
  private userId: string;

  constructor(userId: string) {
    this.userId = userId;
  }

  private sanitizeForCloud(type: string, data: unknown): unknown {
    if (!data) return data;

    // ✅ 全エンティティ共通: undefined を深く除去
    const cleaned = deepStripUndefined(data);

    // ここでローカル専用フィールドを落としたいなら type ごとに増やす
    // （今の 'document' 判定は多分使われてないので、必要になったら追加でOK）
    return cleaned;
  }

  private sanitizeFromCloud(type: string, data: unknown): unknown {
    if (!data) return data;
    const stripped = deepStripUndefined(data);
    const sanitized = sanitizeBlobUrlsDeep(stripped);
    if (sanitized.changed) {
      console.warn(
        "[CloudSyncAdapter] sanitize_blob_url_from_cloud",
        sanitizeForLog({
          type,
          id: data?.id,
          fixes: sanitized.fixes,
        }),
      );
    }
    return sanitized.value;
  }

  async pullDiff(
    since: number,
  ): Promise<{ changes: unknown[]; serverTime: number }> {
    console.log("🔄 [CloudSyncAdapter] pullDiff START", {
      since,
      userId: this.userId,
    });
    const changes: unknown[] = [];

    if (!firestoreDb) {
      console.warn(
        "⚠️ [CloudSyncAdapter] firestoreDb is not initialized. Skipping pullDiff.",
      );
      return { changes: [], serverTime: Date.now() };
    }

    try {
      const sinceTimestamp = Timestamp.fromMillis(since);
      const startAfterFn = (Firestore as any).startAfter as
        | undefined
        | ((snapshot: unknown) => any);

      // cards
      {
        const ref = collection(firestoreDb, `users/${this.userId}/cards`);

        let lastDoc: unknown = null;
        let total = 0;

        while (true) {
          const constraints: unknown[] = [
            where("updatedAt", ">", sinceTimestamp),
            orderBy("updatedAt", "asc"),
            limit(PAGE_SIZE),
          ];

          // typings に startAfter が無い環境でも動くよう any 経由で呼ぶ
          if (startAfterFn && lastDoc)
            constraints.splice(2, 0, startAfterFn(lastDoc));

          const qy = query(ref, ...constraints);
          const snap = await getDocs(qy);
          total += snap.size;

          snap.forEach((d) => {
            changes.push({
              type: "card",
              id: d.id,
              data: this.sanitizeFromCloud("card", d.data()),
            });
          });

          // startAfter が無い環境では1ページで止める（現状より悪化させない）
          if (!startAfterFn || snap.empty || snap.size < PAGE_SIZE) break;
          lastDoc = snap.docs[snap.docs.length - 1] ?? null;
        }

        console.log(`[CloudSyncAdapter] Remote cards found: ${total}`);
      }

      // folders
      {
        const ref = collection(firestoreDb, `users/${this.userId}/folders`);

        let lastDoc: unknown = null;
        let total = 0;

        while (true) {
          const constraints: unknown[] = [
            where("updatedAt", ">", sinceTimestamp),
            orderBy("updatedAt", "asc"),
            limit(PAGE_SIZE),
          ];

          if (startAfterFn && lastDoc)
            constraints.splice(2, 0, startAfterFn(lastDoc));

          const qy = query(ref, ...constraints);
          const snap = await getDocs(qy);
          total += snap.size;

          snap.forEach((d) => {
            changes.push({
              type: "folder",
              id: d.id,
              data: this.sanitizeFromCloud("folder", d.data()),
            });
          });

          if (!startAfterFn || snap.empty || snap.size < PAGE_SIZE) break;
          lastDoc = snap.docs[snap.docs.length - 1] ?? null;
        }

        console.log(`[CloudSyncAdapter] Remote folders found: ${total}`);
      }

      // userSettings (top-level document)
      {
        const settingsRef = doc(firestoreDb, "userSettings", this.userId);
        const snap = await getDoc(settingsRef);
        if (snap.exists()) {
          const data: unknown = this.sanitizeFromCloud(
            "userSetting",
            snap.data(),
          );
          const updatedAt =
            data?.updatedAt?.toMillis?.() ??
            data?.updatedAt?.getTime?.() ??
            (data?.updatedAt instanceof Date ? data.updatedAt.getTime() : 0);
          if (!since || updatedAt > since) {
            changes.push({ type: "userSetting", id: snap.id, data });
          }
        }
      }

      console.log(
        `🔄 [CloudSyncAdapter] pullDiff SUCCESS. Total changes: ${changes.length}`,
      );
      return { changes, serverTime: Date.now() };
    } catch (error) {
      console.error("❌ [CloudSyncAdapter] pullDiff ERROR:", error);
      throw error;
    }
  }

  async pushBatch(
    changes: unknown[],
  ): Promise<{ successIds: string[]; failedIds: string[]; error?: unknown }> {
    console.log(
      `📤 [CloudSyncAdapter] pushBatch START. Count: ${changes.length}`,
    );
    const successIds: string[] = [];
    const failedIds: string[] = [];

    try {
      if (!firestoreDb) {
        console.error(
          "❌ [CloudSyncAdapter] firestoreDb is null during pushBatch",
        );
        return {
          successIds: [],
          failedIds: changes.map((c) => c.id),
          error: new Error("Firestore not initialized"),
        };
      }

      const chunks = chunkChangesBySize(changes);
      let firstError: unknown = undefined;

      for (const chunk of chunks) {
        const batch = writeBatch(firestoreDb);
        const chunkIds: string[] = [];

        for (const change of chunk) {
          const { type, id, data } = change;
          const col = COLLECTION_BY_TYPE[type] ?? `${type}s`; // 保険
          console.log(`   - Adding to batch: ${col}/${id}`);

          const docRef =
            type === "userSetting"
              ? doc(firestoreDb, "userSettings", id || this.userId)
              : doc(firestoreDb, `users/${this.userId}/${col}`, id);

          const sanitized = this.sanitizeForCloud(type, data);

          // sanitized が null とか来たら普通に事故るので最低限の防御
          if (!sanitized || typeof sanitized !== "object") {
            throw new Error(
              `Invalid payload for ${type}/${id}: expected object`,
            );
          }

          batch.set(
            docRef,
            {
              ...sanitized,
              updatedAt: cloudUpdatedAt(),
            },
            { merge: true },
          );

          chunkIds.push(id);
        }

        try {
          console.log(`   - Committing batch... (ops=${chunkIds.length})`);
          await batch.commit();
          successIds.push(...chunkIds);
        } catch (error) {
          console.error(
            "❌ [CloudSyncAdapter] pushBatch chunk commit ERROR:",
            error,
          );
          failedIds.push(...chunkIds);
          if (!firstError) firstError = error;
          // 次のチャンクへ（成功分は残す）
        }
      }

      if (failedIds.length > 0) {
        return { successIds, failedIds, error: firstError };
      }

      console.log("📤 [CloudSyncAdapter] pushBatch SUCCESS");
      return { successIds, failedIds };
    } catch (error) {
      console.error("❌ [CloudSyncAdapter] pushBatch ERROR:", error);
      return {
        successIds: [],
        failedIds: changes.map((c) => c.id),
        error,
      };
    }
  }

  async pullFull(entityIds: string[]): Promise<any[]> {
    const results: unknown[] = [];

    for (const id of entityIds) {
      if (!firestoreDb)
        throw new Error("Firebase Firestore is not initialized.");

      // card
      {
        const snap = await getDocs(
          query(
            collection(firestoreDb, `users/${this.userId}/cards`),
            where("id", "==", id),
          ),
        );
        if (!snap.empty) {
          results.push({
            type: "card",
            id,
            data: this.sanitizeFromCloud("card", snap.docs[0].data()),
          });
          continue;
        }
      }

      // folder
      {
        const snap = await getDocs(
          query(
            collection(firestoreDb, `users/${this.userId}/folders`),
            where("id", "==", id),
          ),
        );
        if (!snap.empty) {
          results.push({
            type: "folder",
            id,
            data: this.sanitizeFromCloud("folder", snap.docs[0].data()),
          });
          continue;
        }
      }

      // userSetting
      {
        const snap = await getDoc(
          doc(firestoreDb, "userSettings", this.userId),
        );
        if (snap.exists()) {
          results.push({
            type: "userSetting",
            id: this.userId,
            data: this.sanitizeFromCloud("userSetting", snap.data()),
          });
        }
      }
    }

    return results;
  }
}

import type {
  INetworkMonitor,
  BatchConstraint,
} from "../interfaces/ISyncService";
import type { NetworkStatus, SyncContextSource } from "../../types/telemetry";

/**
 * NetworkMonitor: ネットワーク状態を監視し、実測値ベースで健全性を判断
 * 状態遷移にヒステリシス（履歴効果）を持たせ、頻繁な揺れを防ぐ
 */
export class NetworkMonitor implements INetworkMonitor {
  private _status: NetworkStatus = "good";
  private consecutiveSuccesses = 0;
  private consecutiveFailures = 0;
  private recentDurations: number[] = [];
  private listeners: Array<(status: NetworkStatus) => void> = [];

  private readonly DURATION_WINDOW = 5; // 直近5回の平均を取る

  // 状態遷移の閾値
  private readonly THRESHOLDS = {
    EXCELLENT_SUCCESS_COUNT: 5,
    GOOD_SUCCESS_COUNT: 3,
    POOR_ERROR_RATE: 0.1,
    RTT_SLOW: 2000,
    RTT_FAST: 100,
  };

  private handleOnline = () => {
    console.log("[NetworkMonitor] Network is online");
    this.updateStatus();
    // 復帰時に即座にgoodに戻す試み（updateStatus内でのロジックに依存）
    if (this._status === "offline") {
      this._status = "poor"; // リセット
      this.notifyListeners();
    }
  };

  private handleOffline = () => {
    console.log("[NetworkMonitor] Network is offline");
    this._status = "offline";
    this.notifyListeners();
  };

  constructor() {
    if (typeof window !== "undefined") {
      window.addEventListener("online", this.handleOnline);
      window.addEventListener("offline", this.handleOffline);
    }
  }

  destroy() {
    if (typeof window !== "undefined") {
      window.removeEventListener("online", this.handleOnline);
      window.removeEventListener("offline", this.handleOffline);
    }
  }

  get status(): NetworkStatus {
    return this._status;
  }

  /**
   * バッチ制約を環境コンテキストに応じて返す
   */
  getBatchConstraint(context: SyncContextSource): BatchConstraint {
    // ユーザー主導の同期は最優先
    if (context === "user_initiated") {
      return {
        maxSize: 100,
        concurrency: 3,
        timeoutMs: 30000,
      };
    }

    // ネットワーク状態に応じた制約
    const baseConstraint = this.getBaseConstraintByNetwork();

    // バックグラウンドは控えめに
    if (context === "background") {
      return {
        maxSize: Math.min(baseConstraint.maxSize, 20),
        concurrency: 1,
        timeoutMs: 10000,
      };
    }

    return baseConstraint;
  }

  private getBaseConstraintByNetwork(): BatchConstraint {
    const avgDuration = this.getAverageDuration();

    switch (this._status) {
      case "excellent":
        return { maxSize: 50, concurrency: 2, timeoutMs: 20000 };
      case "good":
        return { maxSize: 30, concurrency: 1, timeoutMs: 15000 };
      case "poor":
        return { maxSize: 10, concurrency: 1, timeoutMs: 10000 };
      case "offline":
        return { maxSize: 0, concurrency: 0, timeoutMs: 0 };
    }
  }

  /**
   * 同期結果を報告し、状態遷移を判定
   */
  reportResult(success: boolean, durationMs: number): void {
    // 持続時間の記録
    this.recentDurations.push(durationMs);
    if (this.recentDurations.length > this.DURATION_WINDOW) {
      this.recentDurations.shift();
    }

    // 連続成功/失敗のカウント
    if (success) {
      this.consecutiveSuccesses++;
      this.consecutiveFailures = 0;
    } else {
      this.consecutiveFailures++;
      this.consecutiveSuccesses = 0;
    }

    // 状態遷移の判定
    this.updateStatus();
  }

  private updateStatus(): void {
    const avgDuration = this.getAverageDuration();
    const oldStatus = this._status;

    // オフライン判定（即座に降格）
    if (!navigator.onLine) {
      this._status = "offline";
    }
    // Poor判定（エラー率または極端な遅延で即座に降格）
    else if (
      this.consecutiveFailures >= 2 ||
      avgDuration > this.THRESHOLDS.RTT_SLOW
    ) {
      this._status = "poor";
    }
    // Poor -> Good への昇格（慎重に、連続成功が必要）
    else if (
      this._status === "poor" &&
      this.consecutiveSuccesses >= this.THRESHOLDS.GOOD_SUCCESS_COUNT
    ) {
      this._status = "good";
    }
    // Good -> Excellent への昇格（さらに慎重に）
    else if (
      this._status === "good" &&
      this.consecutiveSuccesses >= this.THRESHOLDS.EXCELLENT_SUCCESS_COUNT &&
      avgDuration < this.THRESHOLDS.RTT_FAST
    ) {
      this._status = "excellent";
    }
    // Offline -> Poor への復帰
    else if (this._status === "offline" && navigator.onLine) {
      this._status = "poor"; // 復帰直後は慎重にpoorから開始
    }

    // 状態変化があればリスナーに通知
    if (oldStatus !== this._status) {
      console.log(
        `[NetworkMonitor] Status changed: ${oldStatus} -> ${this._status}`,
      );
      this.notifyListeners();
    }
  }

  private getAverageDuration(): number {
    if (this.recentDurations.length === 0) return 100; // デフォルト値
    return (
      this.recentDurations.reduce((a, b) => a + b, 0) /
      this.recentDurations.length
    );
  }

  /**
   * 状態変化のリスナー登録
   */
  subscribe(callback: (status: NetworkStatus) => void): () => void {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== callback);
    };
  }

  private notifyListeners(): void {
    this.listeners.forEach((listener) => listener(this._status));
  }
}

import { firestoreDb } from "../firebase";
import {
  collection,
  addDoc,
  serverTimestamp,
  Timestamp,
  onSnapshot,
  doc,
  query,
  where,
  updateDoc,
} from "firebase/firestore";
import type {
  SecurityEventType,
  SecurityLog,
  SecurityMetadata,
} from "../../types/telemetry";

/**
 * リスク検知ルールの定義
 * クライアントサイドでの検知ポリシー
 */
interface DetectionRule {
  type: SecurityEventType;
  riskScore: number; // イベントごとの加算スコア
  alwaysTrigger?: boolean; // 閾値なしで即座に加算するか
  timeWindowMs?: number; // 監視窓（ミリ秒）
  countThreshold?: number; // 閾値（回数）
}

/**
 * 異常検知ルールとRiskScore設計に基づく定義
 * @see docs/データベース/異常検知ルールとRiskScore設計.md
 */
const DETECTION_RULES: DetectionRule[] = [
  // 認証異常
  {
    type: "LOGIN_FAILED",
    riskScore: 5,
    timeWindowMs: 5 * 60 * 1000,
    countThreshold: 1,
  },
  { type: "SYNC_AUTH_ERROR", riskScore: 10, alwaysTrigger: true },

  // 端末異常
  { type: "ACCESS_DENIED_REVOKED", riskScore: 30, alwaysTrigger: true },

  // 重要操作失敗
  { type: "SENSITIVE_OP_REVOKED", riskScore: 20, alwaysTrigger: true },

  // 管理操作
  { type: "ADMIN_DEVICE_REVOKE", riskScore: 10, alwaysTrigger: true },
  { type: "ADMIN_ACCOUNT_LOCK", riskScore: 50, alwaysTrigger: true },

  // 技術的異常（以前のルールも保持）
  {
    type: "LOCK_CONTENTION_EXCESS",
    riskScore: 7,
    timeWindowMs: 5 * 60 * 1000,
    countThreshold: 10,
  },
  {
    type: "SYNC_CONFLICT_EXCESS",
    riskScore: 3,
    timeWindowMs: 5 * 60 * 1000,
    countThreshold: 10,
  },
];

/**
 * セキュリティ状態の定義
 */
export interface SecurityState {
  isLocked: boolean;
  requires2FA: boolean;
  alerts: unknown[];
}

/**
 * SecurityMonitor: セキュリティイベントの監視と異常検知を行うクラス
 */
export class SecurityMonitor {
  private userId: string;
  private deviceId: string;
  private eventHistory: { type: SecurityEventType; timestamp: number }[] = [];
  private currentRiskScore: number = 0;
  private lastEvaluationTime: number = Date.now();
  private internalState: SecurityState = {
    isLocked: false,
    requires2FA: false,
    alerts: [],
  };

  constructor(userId: string, deviceId: string) {
    this.userId = userId;
    this.deviceId = deviceId;
    this.loadState();
  }

  /**
   * イベントを記録し、異常検知を実行する
   */
  async logEvent(
    type: SecurityEventType,
    metadata: SecurityMetadata = {},
  ): Promise<void> {
    const now = Date.now();
    this.eventHistory.push({ type, timestamp: now });

    // 履歴のクリーンアップ (古いイベントを削除)
    // 最大の時間窓を持つルールに合わせる (ここでは10分程度あれば十分)
    const maxWindow = 10 * 60 * 1000;
    this.eventHistory = this.eventHistory.filter(
      (e) => e.timestamp > now - maxWindow,
    );

    // ログをFirestoreへ送信
    await this.sendSecurityLog(type, metadata);

    // ルール評価
    this.evaluateRules(type);

    // 永続化
    this.saveState();
  }

  /**
   * 異常検知ルールの評価
   */
  private evaluateRules(triggerType: SecurityEventType): void {
    const now = Date.now();
    let scoreAdded = 0;

    for (const rule of DETECTION_RULES) {
      if (rule.type !== triggerType) continue;

      let shouldTrigger = false;

      if (rule.alwaysTrigger) {
        shouldTrigger = true;
      } else if (rule.timeWindowMs && rule.countThreshold) {
        const recentCount = this.eventHistory.filter(
          (e) => e.type === rule.type && e.timestamp > now - rule.timeWindowMs!,
        ).length;
        // 今回のイベントで閾値に達した、あるいは超えている場合に加算（多重加算防止は簡易）
        if (recentCount >= rule.countThreshold) {
          shouldTrigger = true;
        }
      }

      if (shouldTrigger) {
        console.warn(
          `[Security] Risk score added: +${rule.riskScore} by ${rule.type}`,
        );
        this.currentRiskScore += rule.riskScore;
        scoreAdded += rule.riskScore;
      }
    }

    // 減衰処理（自然復旧）
    this.applyDecay(now);

    // 上限キャップ (0-100)
    this.currentRiskScore = Math.min(100, Math.max(0, this.currentRiskScore));
  }

  /**
   * リスクスコアの減衰処理
   * 1時間ごとの減算処理 (decayPerHour = 3)
   */
  private applyDecay(now: number): void {
    const hoursElapsed = (now - this.lastEvaluationTime) / (1000 * 60 * 60);
    if (hoursElapsed > 0) {
      const decay = Math.floor(hoursElapsed * 3); // 1時間で3減少
      if (decay > 0) {
        this.currentRiskScore = Math.max(0, this.currentRiskScore - decay);
        this.lastEvaluationTime = now;
      }
    }
  }

  /**
   * Firestoreへセキュリティログを送信
   */
  private async sendSecurityLog(
    type: SecurityEventType,
    metadata: SecurityMetadata,
  ): Promise<void> {
    try {
      if (!firestoreDb) {
        console.warn(
          "[Security] firestoreDb is undefined. Skipping security log.",
        );
        return;
      }
      const logData: Omit<SecurityLog, "logId"> = {
        userId: this.userId,
        deviceId: this.deviceId,
        eventType: type,
        severity: this.getSeverity(type),
        source: "client",
        isUserVisible: this.isUserVisible(type),
        description: this.getDescription(type),
        metadata,
        occurredAt: serverTimestamp(),
      };

      await addDoc(
        collection(firestoreDb, `users/${this.userId}/securityLogs`),
        logData,
      );
    } catch (error) {
      console.error("[Security] Failed to send log:", error);
      // 送信失敗自体もリスクだが、無限ループ防止のためここでは握りつぶす
    }
  }

  /**
   * イベントタイプから重要度を判定
   */
  private getSeverity(
    type: SecurityEventType,
  ): "info" | "warning" | "critical" {
    switch (type) {
      case "ACCESS_DENIED_REVOKED":
      case "LOCK_CONTENTION_EXCESS":
      case "ADMIN_ACCOUNT_LOCK":
        return "critical";
      case "DEVICE_REVOKED":
      case "SYNC_AUTH_ERROR":
      case "SYNC_CONFLICT_EXCESS":
      case "ADMIN_DEVICE_REVOKE":
      case "SENSITIVE_OP_REVOKED":
        return "warning";
      default:
        return "info";
    }
  }

  /**
   * ユーザーに表示すべきかどうか
   */
  private isUserVisible(type: SecurityEventType): boolean {
    // 基本的に内部的な異常検知はユーザーに見せないが、
    // アカウントロックや新しいデバイス登録などは見せる
    switch (type) {
      case "DEVICE_NEW_REGISTER":
      case "LOGIN_SUCCESS":
      case "DEVICE_REVOKED":
      case "ADMIN_ACCOUNT_LOCK":
        return true;
      default:
        return false;
    }
  }

  /**
   * デフォルトの説明文
   */
  private getDescription(type: SecurityEventType): string {
    // 簡易的なマッピング。多言語対応が必要な場合は別途翻訳リソースを使う。
    const descMap: Record<SecurityEventType, string> = {
      LOGIN_SUCCESS: "ログインに成功しました",
      LOGIN_FAILED: "ログインに失敗しました",
      DEVICE_REVOKED: "デバイス登録が解除されました",
      ACCESS_DENIED_REVOKED: "無効化されたデバイスからのアクセスを拒否しました",
      SYNC_AUTH_ERROR: "同期の認証エラーが発生しました",
      SENSITIVE_OP_REVOKED: "権限のない重要な操作が拒否されました",
      DEVICE_NEW_REGISTER: "新しいデバイスが登録されました",
      LOCK_CONTENTION_EXCESS:
        "同期ロックの頻繁な競合（奪取ループ）を検知しました",
      SYNC_CONFLICT_EXCESS: "データ競合が異常に多発しています",
      ADMIN_DEVICE_REVOKE: "管理者によりデバイスが解除されました",
      ADMIN_ACCOUNT_LOCK: "管理者によりアカウントがロックされました",
      ADMIN_LOG_EXPORT: "監査ログが出力されました",
    };
    return descMap[type] || "セキュリティイベントが発生しました";
  }

  /**
   * 現在のセキュリティ状態（SafeModeかどうか等）を取得
   */
  getSecurityStatus(): { isSafeMode: boolean; riskScore: number } {
    // リスクスコア 10以上で SafeMode
    return {
      isSafeMode: this.currentRiskScore >= 10,
      riskScore: this.currentRiskScore,
    };
  }

  private unsubscribeMetadata: (() => void) | null = null;
  private unsubscribeNotifications: (() => void) | null = null;

  /**
   * リアルタイム監視を開始する
   * - ユーザーメタデータ (ロック状態, 2FA)
   * - セキュリティ通知
   */
  startMonitoring(onStateChange: (state: SecurityState) => void): void {
    if (!firestoreDb) {
      console.error(
        "[Security] firestoreDb is undefined. Cannot start monitoring.",
      );
      return;
    }
    // 1. メタデータ監視
    this.unsubscribeMetadata = onSnapshot(
      doc(firestoreDb, `users/${this.userId}`),
      (snapshot) => {
        if (snapshot.exists()) {
          const data = snapshot.data();
          this.internalState.isLocked = data.isAccountLocked === true;
          this.internalState.requires2FA = data.requires2FA === true;

          onStateChange({ ...this.internalState });
        }
      },
      (error) => {
        console.error("[Security] Metadata monitoring failed:", error);
      },
    );

    // 2. 通知監視 (SecurityAlertの未読)
    const q = query(
      collection(firestoreDb, `users/${this.userId}/notifications`),
      where("type", "==", "SECURITY_ALERT"),
      where("read", "==", false),
    );

    this.unsubscribeNotifications = onSnapshot(
      q,
      (snapshot) => {
        this.internalState.alerts = snapshot.docs.map((doc) => ({
          id: doc.id,
          ...doc.data(),
        }));

        onStateChange({ ...this.internalState });
      },
      (error) => {
        // Permisson errors are expected if rules are not set up. Suppress to avoid spam.
        if (error.code !== "permission-denied") {
          console.warn(
            "[Security] Notification monitoring failed (non-permission error):",
            error,
          );
        }
      },
    );
  }

  /**
   * 通知を既読にする
   */
  async dismissAlert(alertId: string): Promise<void> {
    try {
      if (!firestoreDb)
        throw new Error("Firebase Firestore is not initialized.");
      const alertRef = doc(
        firestoreDb,
        `users/${this.userId}/notifications`,
        alertId,
      );
      await updateDoc(alertRef, { read: true });
    } catch (error) {
      console.error("[Security] Failed to dismiss alert:", error);
    }
  }

  /**
   * 監視を停止する
   */
  stopMonitoring(): void {
    if (this.unsubscribeMetadata) {
      this.unsubscribeMetadata();
      this.unsubscribeMetadata = null;
    }
    if (this.unsubscribeNotifications) {
      this.unsubscribeNotifications();
      this.unsubscribeNotifications = null;
    }
  }

  /**
   * 状態の保存 (localStorage)
   */
  private saveState(): void {
    localStorage.setItem(
      `security_score_${this.userId}`,
      this.currentRiskScore.toString(),
    );
    localStorage.setItem(
      `security_last_eval_${this.userId}`,
      this.lastEvaluationTime.toString(),
    );
  }

  /**
   * 状態の読み込み
   */
  private loadState(): void {
    const score = localStorage.getItem(`security_score_${this.userId}`);
    const time = localStorage.getItem(`security_last_eval_${this.userId}`);
    if (score) this.currentRiskScore = parseInt(score, 10);
    if (time) this.lastEvaluationTime = parseInt(time, 10);
  }
}

import { Timestamp } from "firebase/firestore";
import type { SubjectiveScore } from "@/utils/reviewUtils";

export type ReviewAlgorithmInput = {
  card: {
    memoryStability?: number | null;
    currentLevel?: number | null;
    level?: number | null;
    nextReviewDate?: Date | Timestamp | null;
    lastReviewAt?: Date | Timestamp | null;
    recoveryRemaining?: number | null;
    reviewCount?: number | null; // Added

    // ✅ Added: difficulty (0..1). Higher = more error-prone / harder for this user.
    difficulty?: number | null;
  };
  subjectiveScore: SubjectiveScore;
  now?: Date;
};

export type ReviewAlgorithmResult = {
  memoryStability: number;
  nextReviewDate: Date;
  lastReviewAt: Date;
  lastSubjectiveScore: SubjectiveScore;
  recoveryRemaining: number;
  intervalDays: number;
  delayDays: number;
  reviewCount: number; // Added

  // ✅ Added
  difficulty: number;
};

// Constants
const MIN_STABILITY = 0.01; // Prevent division by zero
const MAX_STABILITY = 1.0;
const MAX_INTERVAL_DAYS = 90;

// ✅ Difficulty constants (pragmatic defaults)
const MIN_DIFFICULTY = 0.0;
const MAX_DIFFICULTY = 1.0;

// EMA smoothing factor (smaller = more stable, larger = more reactive)
const DIFFICULTY_ALPHA = 0.1;

// Interval brake strength (0.0..1.0). Example: 0.30 => max 30% shorter at difficulty=1
const DIFFICULTY_INTERVAL_BRAKE = 0.3;

// Helper: Convert Firestore Timestamp or Date to Date
const toDate = (value?: Date | Timestamp | null): Date | null => {
  if (!value) return null;
  if (value instanceof Date) return value;
  if (typeof (value as any)?.toDate === "function")
    return (value as any).toDate();
  if (typeof value === "object") {
    const seconds =
      typeof (value as any)?.seconds === "number"
        ? (value as any).seconds
        : typeof (value as any)?._seconds === "number"
          ? (value as any)._seconds
          : null;
    const nanoseconds =
      typeof (value as any)?.nanoseconds === "number"
        ? (value as any).nanoseconds
        : typeof (value as any)?._nanoseconds === "number"
          ? (value as any)._nanoseconds
          : 0;
    if (seconds !== null) {
      const ms = seconds * 1000 + Math.floor(nanoseconds / 1e6);
      const d = new Date(ms);
      return Number.isNaN(d.getTime()) ? null : d;
    }
  }
  const parsed = new Date(value as any);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

// Helper: Calculate day difference
const diffDays = (a: Date, b: Date): number => {
  const msA = new Date(a).setHours(0, 0, 0, 0);
  const msB = new Date(b).setHours(0, 0, 0, 0);
  return Math.floor((msA - msB) / (1000 * 60 * 60 * 24));
};

// Clamp stability to valid range (0, 1]
const clampStability = (s: number): number => {
  return Math.max(MIN_STABILITY, Math.min(MAX_STABILITY, s));
};

// ✅ Clamp to [0,1]
const clamp01 = (x: number): number => {
  return Math.max(0, Math.min(1, x));
};

// ✅ Clamp difficulty to [0,1]
const clampDifficulty = (d: number): number => {
  return Math.max(MIN_DIFFICULTY, Math.min(MAX_DIFFICULTY, d));
};

// Normalize legacy level (0-5) to new stability (0-1)
const legacyLevelToStability = (level: number): number => {
  // Map levels 0-5 to stability 0.1-0.9
  const normalized = 0.1 + (Math.min(5, Math.max(0, level)) / 5) * 0.8;
  return clampStability(normalized);
};

// Get initial stability for a card
export const getInitialStability = (
  memoryStability?: number | null,
  legacyLevel?: number | null,
): number => {
  // If we have a valid 0-1 stability, use it directly
  if (typeof memoryStability === "number" && Number.isFinite(memoryStability)) {
    if (memoryStability > 0 && memoryStability <= 1) {
      return clampStability(memoryStability);
    }
    // Legacy format (5-100 days): convert to 0-1 range
    if (memoryStability > 1 && memoryStability <= 100) {
      return clampStability((memoryStability - 5) / 95);
    }
  }

  // Fall back to legacy level if available
  if (typeof legacyLevel === "number" && Number.isFinite(legacyLevel)) {
    return legacyLevelToStability(legacyLevel);
  }

  // Default: 30% stability for new cards
  return 0.3;
};

// ✅ Initial difficulty (0..1)
// “測る”んじゃなくて、カードの挙動から“推定する”ための初期値。
// 既存値があればそれを採用。なければ stability から雑に推定（新規でも極端にならないように弱める）。
export const getInitialDifficulty = (
  difficulty?: number | null,
  stability?: number | null,
): number => {
  if (typeof difficulty === "number" && Number.isFinite(difficulty)) {
    return clampDifficulty(difficulty);
  }

  // Derive a conservative default from stability if available:
  // Higher stability => lower difficulty, but dampened so new cards aren't instantly "hardest".
  if (typeof stability === "number" && Number.isFinite(stability)) {
    const derived = (1 - clamp01(stability)) * 0.6; // 0..0.6 range
    return clampDifficulty(derived);
  }

  // Neutral-ish default
  return 0.35;
};

/**
 * Calculate next review interval based on stability
 * Formula: D = 1 + 100 × S^2.5
 */
const calculateIntervalDays = (stability: number): number => {
  const days = 1 + 100 * Math.pow(stability, 2.5);
  return Math.max(1, Math.min(MAX_INTERVAL_DAYS, Math.round(days)));
};

/**
 * Update stability based on subjective score
 *
 * Score 0 (忘れた): S' = S × 0.5
 * Score 1 (あいまい): S' = S × 0.8
 * Score 2 (OK): S' = S + (1-S) × 0.1
 * Score 3 (余裕): S' = S + (1-S) × 0.25
 */
const updateStability = (
  currentStability: number,
  score: SubjectiveScore,
): number => {
  let newStability: number;

  switch (score) {
    case 0: // 忘れた - 50% decrease (Factor 0.5)
      newStability = currentStability * 0.5;
      break;
    case 1: // あいまい - 20% decrease
      newStability = currentStability * 0.8;
      break;
    case 2: // 覚えた - 10% of remaining growth
      newStability = currentStability + (1 - currentStability) * 0.1;
      break;
    case 3: // 余裕 - 25% of remaining growth
      newStability = currentStability + (1 - currentStability) * 0.25;
      break;
    default:
      newStability = currentStability;
  }

  return clampStability(newStability);
};

// ✅ Subjective score -> "fail-ish" (0..1)
// This is NOT truth, just a pragmatic signal.
// 0 (Forgot) : 1.0
// 1 (Hard)   : 0.6
// 2 (Good)   : 0.2
// 3 (Easy)   : 0.0
const scoreToFailish = (score: SubjectiveScore): number => {
  switch (score) {
    case 0:
      return 1.0;
    case 1:
      return 0.6;
    case 2:
      return 0.2;
    case 3:
      return 0.0;
    default:
      return 0.2;
  }
};

// ✅ Update difficulty via EMA:
// d' = d*(1-α) + failish*α
const updateDifficulty = (
  currentDifficulty: number,
  score: SubjectiveScore,
): number => {
  const failish = scoreToFailish(score);
  const next =
    currentDifficulty * (1 - DIFFICULTY_ALPHA) + failish * DIFFICULTY_ALPHA;
  return clampDifficulty(next);
};

// ✅ Apply difficulty as a mild interval brake (safe and explainable internally)
const applyDifficultyBrakeToInterval = (
  baseIntervalDays: number,
  difficulty: number,
): number => {
  const factor = 1 - DIFFICULTY_INTERVAL_BRAKE * clampDifficulty(difficulty); // [1-k, 1]
  const adjusted = Math.round(baseIntervalDays * factor);
  return Math.max(1, Math.min(MAX_INTERVAL_DAYS, adjusted));
};

/**
 * Main review algorithm
 */
export const computeNextReview = ({
  card,
  subjectiveScore,
  now = new Date(),
  delayBonusEnabled = false,
}: ReviewAlgorithmInput & {
  delayBonusEnabled?: boolean;
}): ReviewAlgorithmResult => {
  const c: unknown = card as any;
  // Get current stability (with legacy conversion)
  const legacyLevel = (card.currentLevel ??
    c.current_level ??
    card.level ??
    c.level ??
    null) as any;
  const currentStability = getInitialStability(
    (card.memoryStability ?? c.memory_stability ?? null) as any,
    legacyLevel,
  );

  // ✅ Get current difficulty
  const currentDifficulty = getInitialDifficulty(
    (card.difficulty ?? c.difficulty ?? null) as any,
    currentStability,
  );

  // Calculate delay (days overdue)
  const plannedDate = toDate(
    (card.nextReviewDate ?? c.next_review_date ?? null) as any,
  );
  const diff = plannedDate ? diffDays(now, plannedDate) : 0;
  const delayDays = Math.max(0, diff);

  // Update stability based on review result
  let newStability = updateStability(currentStability, subjectiveScore);

  // Delay Bonus Logic
  if (delayBonusEnabled && delayDays > 0) {
    // Formula: S' = S' * (1 + log2(1 + D))
    const bonusFactor = 1 + Math.log2(1 + delayDays);
    newStability = clampStability(newStability * bonusFactor);
  }

  // ✅ Update difficulty AFTER seeing the result (and independent from delay to avoid "busy life" pollution)
  const newDifficulty = updateDifficulty(currentDifficulty, subjectiveScore);

  // Recovery Mode Removed (kept for schema compatibility)
  const recoveryRemaining = 0;

  // Calculate next interval (stability base)
  const baseIntervalDays = calculateIntervalDays(newStability);

  // ✅ Apply difficulty brake (mild encourage for “problem cards”)
  const intervalDays = applyDifficultyBrakeToInterval(
    baseIntervalDays,
    newDifficulty,
  );

  // Calculate next review date
  const nextReviewDate = new Date(now);
  nextReviewDate.setDate(nextReviewDate.getDate() + intervalDays);
  nextReviewDate.setHours(0, 0, 0, 0);

  // Increment review count
  const currentReviewCount = (card.reviewCount ?? c.review_count ?? 0) as any;
  const reviewCount = currentReviewCount + 1;

  return {
    memoryStability: newStability,
    nextReviewDate,
    lastReviewAt: now,
    lastSubjectiveScore: subjectiveScore,
    recoveryRemaining,
    intervalDays,
    delayDays,
    reviewCount,

    // ✅ Return difficulty so caller can persist it
    difficulty: newDifficulty,
  };
};

/**
 * Calculate recall probability based on time elapsed
 * Formula: R(t) = e^(-t/S)
 *
 * @param stability Current stability (0-1)
 * @param daysSinceReview Days since last review
 * @returns Recall probability (0-1)
 */
export const calculateRecallProbability = (
  stability: number,
  daysSinceReview: number,
): number => {
  if (stability <= 0) return 0;
  if (daysSinceReview <= 0) return 1;

  // Scale stability for the exponential formula
  const scaledStability = stability * 100;
  return Math.exp(-daysSinceReview / scaledStability);
};

// ============================================================================
// Multiple Choice Integration (4択モード統合)
// ============================================================================

/**
 * 4択モードでの確信度（正解時のみ取得）
 */
export type MultipleChoiceConfidence = "high" | "mid" | "luck";

/**
 * 4択モードの復習メタデータ
 */
export type MultipleChoiceReviewMeta = {
  /** 選択した答えが正解かどうか */
  isCorrect: boolean;

  /** 「分からない」を選択したか（明示的なギブアップ） */
  isUnknown?: boolean;

  /** 正解時の確信度（未入力時は自動的に 'mid' 扱い） */
  confidence?: MultipleChoiceConfidence;

  /** 選択肢表示後から回答までの時間（ミリ秒） */
  choiceTimeMs?: number;
};

/**
 * 4択結果を SubjectiveScore に変換する
 *
 * 変換ルール:
 * - isUnknown === true → 0
 * - isCorrect === false → 0
 * - isCorrect === true:
 *   - confidence === 'high' → 3
 *   - confidence === 'mid' or undefined → 2
 *   - confidence === 'luck' → 1
 *
 * 反応時間による弱い制限:
 * - choiceTimeMs > 9000ms → score を最大 1 に制限
 * - choiceTimeMs > 6000ms → score を最大 2 に制限
 *
 * @param meta 4択モードの復習メタデータ
 * @returns SubjectiveScore (0..3)
 */
export const convertMultipleChoiceToSubjectiveScore = (
  meta: MultipleChoiceReviewMeta,
): SubjectiveScore => {
  // 分からないを選択 or 不正解 → 0
  if (meta.isUnknown === true || meta.isCorrect === false) {
    return 0;
  }

  // 正解時: 確信度から base score を決定
  const confidence = meta.confidence ?? "mid"; // 未入力時は自動的に 'mid'
  let score: SubjectiveScore;

  switch (confidence) {
    case "high":
      score = 3;
      break;
    case "mid":
      score = 2;
      break;
    case "luck":
      score = 1;
      break;
    default:
      score = 2; // fallback
  }

  // 反応時間による弱い制限（オプショナル）
  if (typeof meta.choiceTimeMs === "number" && meta.choiceTimeMs > 0) {
    if (meta.choiceTimeMs > 9000) {
      // 9秒超: 最大 1 に制限（時間かかりすぎ）
      score = Math.min(score, 1) as SubjectiveScore;
    } else if (meta.choiceTimeMs > 6000) {
      // 6秒超: 最大 2 に制限（やや時間かかった）
      score = Math.min(score, 2) as SubjectiveScore;
    }
  }

  return score;
};

