      wrapper.dispatchEvent(
        new KeyboardEvent("keydown", { key: "ArrowLeft", bubbles: true }),
      );
    });

    expect(
      (el.querySelector('[data-testid="study-card"]') as HTMLElement).dataset
        .cardId,
    ).toBe("b");
  });

